import type { SignTemplates } from './types';

export const ariesTemplates: SignTemplates = {
  overall: {
    high: [
      { ko: '화성의 강력한 에너지가 오늘 당신 편에 완전히 서 있습니다. 그 뜨거운 불꽃이 바로 당신만의 추진력이기 때문에, 오늘 내딛는 첫 걸음은 반드시 큰 결과로 이어집니다. 지금 이 순간을 믿고 행동으로 증명하세요.', en: 'Mars\' powerful energy stands fully on your side today, and that blazing fire is your unique drive. What you start now carries unstoppable momentum—the universe is aligned for your first bold move. Trust this moment and let action be your proof.', zh: '火星的强大能量今天完全站在你这边，那熊熊烈火正是你独特的推动力。今天迈出的第一步必定带来丰硕成果，相信此刻并用行动证明自己。', ja: '火星の強力なエネルギーが今日完全にあなたの味方です。その燃える炎はあなただけの推進力であり、今踏み出す一歩は必ず大きな結果につながります。今この瞬間を信じて行動で証明してください。', es: 'La poderosa energía de Marte está completamente de tu lado hoy, y esa llama ardiente es tu impulso único. Lo que inicies ahora lleva un impulso imparable—actúa y demuéstralo con acciones.' },
      { ko: '양자리 특유의 추진력이 오늘 눈부시게 빛납니다. 다른 사람들이 계획만 세울 때 당신은 이미 실행에 옮기는 선구자이기 때문입니다. 망설임을 내려놓고 그 프로젝트의 첫 줄을 지금 당장 써 내려가세요.', en: 'Your Aries drive shines brilliantly today—while others are still planning, you are already the pioneer who acts. This instinct to move first is your greatest gift. Set aside hesitation and write the first line of that project right now.', zh: '白羊座特有的推动力今天耀眼地闪耀。当别人还在计划时，你已经是付诸行动的先驱者。放下犹豫，立刻开始那个项目的第一步。', ja: '牡羊座特有の推進力が今日眩しく輝いています。他の人がまだ計画を立てている時、あなたはすでに行動に移す先駆者だからです。迷いを手放して今すぐそのプロジェクトの最初の一歩を踏み出してください。', es: 'Tu impulso ariano brilla brillantemente hoy—mientras otros aún planifican, tú ya eres el pionero que actúa. Deja la duda atrás y escribe la primera línea de ese proyecto ahora mismo.' },
      { ko: '불의 원소가 활활 타오르며 당신에게 최고의 행운을 가져다주고 있습니다. 이 에너지는 확신을 가진 자에게만 온전히 전달되는 우주의 선물입니다. 자신감을 갑옷처럼 입고 오늘 하루를 정복하세요.', en: 'The fire element blazes at its peak, bringing you the finest luck available. This energy is a cosmic gift that only reaches those who move with conviction. Wear confidence like armor and conquer this day.', zh: '火元素熊熊燃烧，为你带来最好的运气。这股能量是宇宙给予充满信心者的礼物。以自信为铠甲，征服今天。', ja: '火のエレメントが燃え上がり最高の幸運をもたらしています。このエネルギーは確信を持った者だけに届く宇宙の贈り物です。自信を鎧のように身につけて今日を征服してください。', es: 'El elemento fuego arde en su punto máximo, trayéndote la mejor suerte disponible. Esta energía es un regalo cósmico que solo alcanza a quienes actúan con convicción. Viste la confianza como armadura y conquista este día.' },
      { ko: '오늘은 당신이 앞장서서 이끌 때 비로소 모든 것이 순조롭게 풀리는 날입니다. 양자리의 타고난 리더십이 주변 사람들에게 방향을 제시하는 나침반 역할을 하기 때문입니다. 주저하지 말고 먼저 한 발 내딛어 흐름을 만들어가세요.', en: 'Everything flows smoothly today precisely when you step forward and lead. Your innate Aries leadership serves as a compass that gives direction to those around you. Don\'t hesitate—take that first step and create the flow.', zh: '今天当你带头领导时一切都会顺利展开。白羊座天生的领导力为周围的人指引方向。不要犹豫，迈出第一步创造流势。', ja: '今日はあなたが先頭に立って率いる時こそ全てが順調に解決する日です。牡羊座の生まれつきのリーダーシップが周りの人に方向を示す羅針盤の役割を果たすからです。迷わず先に一歩踏み出して流れを作っていってください。', es: 'Todo fluye perfectamente hoy cuando tú tomas la delantera y lideras. Tu liderazgo ariano innato sirve de brújula para quienes te rodean. No dudes—da ese primer paso y crea el flujo.' },
      { ko: '별들이 오늘 당신의 개척 정신을 한껏 축복하고 있습니다. 처음 가는 길을 두려워하지 않는 것, 그것이 바로 양자리가 다른 별자리와 다른 이유입니다. 지금이 새로운 도전에 뛰어들 완벽한 타이밍임을 기억하세요.', en: 'The stars are blessing your pioneering spirit with full force today. Not fearing the uncharted path is precisely what sets Aries apart from every other sign. Remember—this is the perfect moment to leap into new challenges.', zh: '星星今天全力祝福你的开拓精神。不惧怕前无古人的道路，正是白羊座与其他星座不同的原因。记住，现在是跳入新挑战的完美时机。', ja: '星々が今日あなたの開拓精神を大いに祝福しています。初めての道を恐れないこと、それが牡羊座が他の星座と異なる理由です。今が新しい挑戦に飛び込む完璧なタイミングであることを覚えておいてください。', es: 'Las estrellas bendicen tu espíritu pionero con toda su fuerza hoy. No temer el camino inexplorado es exactamente lo que distingue a Aries. Recuerda—este es el momento perfecto para lanzarte a nuevos desafíos.' },
      { ko: '용기 있는 결단이 반드시 큰 보상으로 돌아오는 하루입니다. 화성의 불꽃은 망설이는 자가 아닌 행동하는 자를 통해 타오르기 때문입니다. 직감을 믿고 과감하게 행동하면 오늘 당신의 이야기가 달라집니다.', en: 'Brave decisions are guaranteed to return as great rewards today. The flame of Mars burns through those who act, not those who hesitate. Trust your instinct, act boldly, and your story changes from this very day.', zh: '勇敢的决断今天必定以丰厚回报归来。火星的火焰燃烧在行动者而非犹豫者身上。相信直觉，大胆行动，今天你的故事将焕然一新。', ja: '勇気ある決断が必ず大きな報酬として返ってくる一日です。火星の炎は迷う者ではなく行動する者を通して燃え上がるからです。直感を信じて大胆に行動すれば今日あなたの物語が変わります。', es: 'Las decisiones valientes están garantizadas a regresar como grandes recompensas hoy. La llama de Marte arde a través de quienes actúan, no de quienes dudan. Confía en tu instinto, actúa con audacia y tu historia cambia desde hoy.' },
      { ko: '지배행성 화성이 오늘 유독 강한 에너지를 보내고 있습니다. 이 에너지는 활동적인 일에 투자할수록 몇 배로 증폭되어 돌아오는 특성이 있습니다. 뛰어난 성과를 기대하며 에너지를 아끼지 말고 쏟아내세요.', en: 'Your ruling planet Mars is sending unusually strong energy today. This force multiplies in return the more you invest it in active pursuits. Expect outstanding results—pour your energy out without holding back.', zh: '守护星火星今天发送特别强大的能量。这股能量越投入活跃的事务，就越会成倍地归还。期待出色成果，毫不保留地投入吧。', ja: '支配星の火星が今日特に強いエネルギーを送っています。このエネルギーは活動的なことに投資するほど何倍にも増幅されて戻ってくる特性があります。優れた成果を期待しながらエネルギーを惜しまず注ぎ出してください。', es: 'Tu planeta regente Marte envía una energía inusualmente fuerte hoy. Esta fuerza se multiplica al retornar cuanto más la inviertes en actividades activas. Espera resultados excepcionales—vierte tu energía sin reservas.' },
      { ko: '오늘의 우주적 에너지는 당신의 열정에 날개를 달아주고 있습니다. 열정이란 방향이 있을 때 비로소 결과를 만드는 법이니, 목표를 선명하게 그린 뒤 전력으로 질주하세요. 오늘만큼은 속도가 당신의 가장 강력한 무기입니다.', en: 'Today\'s cosmic energy is giving wings to your passion. Passion only creates results when it has direction, so draw your goal vividly and sprint with full force. Today, speed is your most powerful weapon.', zh: '今天的宇宙能量为你的热情插上翅膀。热情只有有了方向才能创造结果，所以清晰地描绘目标，全力冲刺。今天速度是你最强大的武器。', ja: '今日の宇宙的エネルギーがあなたの情熱に翼を与えています。情熱とは方向がある時こそ結果を生むものなので、目標を鮮明に描いてから全力で疾走してください。今日だけは速度があなたの最も強力な武器です。', es: 'La energía cósmica de hoy da alas a tu pasión. La pasión solo crea resultados cuando tiene dirección, así que dibuja tu meta vívidamente y corre con toda tu fuerza. Hoy, la velocidad es tu arma más poderosa.' },
      { ko: '주변 사람들이 오늘 당신의 활력에 깊이 감화받는 날입니다. 양자리의 불꽃 같은 에너지는 주변을 밝히는 횃불이 되어 공간 전체를 살아 있게 합니다. 긍정적 영향력을 아낌없이 나누면 그 빛이 당신에게 배가되어 돌아옵니다.', en: 'People around you are deeply inspired by your vitality today. Your Aries fire-like energy becomes a torch that illuminates your surroundings and brings the whole space alive. Share your positive influence freely, and that light will return to you doubled.', zh: '周围的人今天深受你的活力感染。白羊座如火焰般的能量成为照亮周围的火炬，让整个空间充满生机。慷慨分享你的正能量，那份光芒将加倍归还于你。', ja: '周りの人が今日あなたの活力に深く感化される日です。牡羊座の炎のようなエネルギーは周りを照らすたいまつとなり空間全体を生き生きとさせます。ポジティブな影響力を惜しみなく分かち合えばその光があなたに倍になって戻ってきます。', es: 'Las personas a tu alrededor están profundamente inspiradas por tu vitalidad hoy. Tu energía de fuego ariana se convierte en una antorcha que ilumina tu entorno. Comparte tu influencia positiva libremente y esa luz te regresará duplicada.' },
      { ko: '양자리의 선구자적 기운이 오늘 완전한 절정에 달했습니다. 남들이 주저하고 멈추는 그 길 위에서 당신만이 앞으로 나아갈 수 있는 것은, 실패를 두려워하지 않는 용기가 이미 당신 안에 있기 때문입니다. 그 길에서 오늘 성공의 씨앗을 심으세요.', en: 'Your Aries pioneering energy reaches its absolute peak today. You alone can advance where others pause and stop, because the courage to not fear failure already lives within you. Plant the seeds of success on that path today.', zh: '白羊座的先驱气运今天达到完全的顶峰。在别人犹豫停步的道路上，只有你能前进，因为不惧失败的勇气已经在你内心。在那条路上今天播下成功的种子。', ja: '牡羊座の先駆者的な気運が今日完全な絶頂に達しました。他の人が躊躇し立ち止まるその道の上であなただけが前に進めるのは、失敗を恐れない勇気がすでにあなたの中にあるからです。その道で今日成功の種を蒔いてください。', es: 'Tu energía pionera de Aries alcanza su pico absoluto hoy. Solo tú puedes avanzar donde otros se detienen, porque el valor de no temer el fracaso ya vive dentro de ti. Siembra las semillas del éxito en ese camino hoy.' },
    ],
    medium: [
      { ko: '평소의 추진력을 조금 늦추고 주변을 살펴보면 숨겨진 기회가 모습을 드러냅니다. 속도를 줄일 때 비로소 보이는 것들이 있고, 그 안정 속에서 다음 도약의 발판을 발견하게 됩니다. 오늘은 달리는 대신 관찰하며 내일의 전략을 세워보세요.', en: 'Slow your usual pace and look around—hidden opportunities begin to reveal themselves. There are things you only see when you reduce speed, and within that stability you discover the foothold for your next leap. Observe today instead of running, and build tomorrow\'s strategy.', zh: '放慢平时的推动力，看看周围，隐藏的机会开始显现。减速时才能看见一些东西，在那份稳定中发现下一次跃进的立足点。今天不要奔跑，而是观察，制定明天的策略。', ja: 'いつもの推進力を少し緩めて周りを見ると隠れたチャンスが姿を現します。速度を落とした時こそ見えるものがあり、その安定の中で次の飛躍の足がかりを発見できます。今日は走る代わりに観察しながら明日の戦略を立ててみてください。', es: 'Reduce tu ritmo habitual y mira alrededor—las oportunidades ocultas comienzan a revelarse. Hay cosas que solo ves cuando reduces la velocidad; dentro de esa estabilidad descubres el apoyo para tu próximo salto. Observa hoy en lugar de correr y construye la estrategia de mañana.' },
      { ko: '에너지가 고르게 분배되는 날이니, 급하게 서두르기보다 꾸준한 페이스를 유지하는 것이 현명합니다. 화성의 에너지조차 균형이 맞을 때 더 오래 지속되고 더 넓게 퍼집니다. 오늘 하루를 마라톤 선수처럼 계산된 호흡으로 달려보세요.', en: 'Energy is evenly distributed today, so maintaining a steady pace is wiser than rushing. Even Mars\' energy lasts longer and spreads wider when balanced. Run today like a marathon runner—with calculated, rhythmic breathing.', zh: '能量均匀分配的一天，保持稳定节奏比急于求成更明智。即使是火星能量，平衡时也能持续更久、传播更广。像马拉松选手一样用有计划的呼吸跑完今天。', ja: 'エネルギーが均等に分配される日なので急がずに着実なペースを維持するのが賢明です。火星のエネルギーでさえバランスが取れている時により長く続き広く広がります。今日一日をマラソン選手のように計算された呼吸で走ってみてください。', es: 'La energía se distribuye uniformemente hoy, por lo que mantener un ritmo constante es más sabio que apresurarse. Incluso la energía de Marte dura más y se extiende más cuando está equilibrada. Corre hoy como un maratonista—con respiración calculada y rítmica.' },
      { ko: '화성의 에너지가 잔잔하게 흐르는 날입니다. 작은 일상 속에 숨겨진 만족감을 찾는 것, 사실 이것이 불꽃을 오래 유지하는 가장 확실한 방법입니다. 오늘 저녁 하루를 돌아보며 세 가지 감사를 적어보세요.', en: 'Mars\' energy flows gently today. Finding hidden satisfaction in small everyday moments is actually the most reliable way to keep the flame burning long. Tonight, look back at your day and write down three things you\'re grateful for.', zh: '火星的能量今天平静地流动。在小小的日常中寻找隐藏的满足感，事实上这是长久保持火焰的最可靠方法。今晚回顾一天，写下三件感恩的事。', ja: '火星のエネルギーが穏やかに流れる日です。小さな日常の中に隠れた満足感を見つけること、実はこれが炎を長く保つ最も確実な方法です。今夜一日を振り返って三つの感謝を書いてみてください。', es: 'La energía de Marte fluye suavemente hoy. Encontrar satisfacción oculta en pequeños momentos cotidianos es en realidad la forma más confiable de mantener la llama ardiendo. Esta noche, mira hacia atrás en tu día y escribe tres cosas por las que estás agradecido/a.' },
      { ko: '오늘은 행동보다 계획에 집중하면 훨씬 좋은 결과를 이끌어낼 수 있습니다. 양자리의 빠른 실행력은 탄탄한 계획 위에 올라설 때 진정한 위력을 발휘하기 때문입니다. 내일의 도전을 차분히 설계하며 에너지를 아껴두세요.', en: 'You\'ll get far better results by focusing on planning rather than action today. Your Aries speed of execution shows its true power when built on a solid plan. Calmly design tomorrow\'s challenge and save your energy.', zh: '今天专注于计划而非行动会带来更好的结果。白羊座快速执行力建立在扎实计划上时才能发挥真正威力。冷静地设计明天的挑战，储备能量。', ja: '今日は行動より計画に集中すると遥かに良い結果を引き出せます。牡羊座の素早い実行力は確固とした計画の上に乗った時こそ真の威力を発揮するからです。明日の挑戦を落ち着いて設計しながらエネルギーを貯めておいてください。', es: 'Obtendrás resultados mucho mejores enfocándote en planificar más que en actuar hoy. Tu velocidad de ejecución ariana muestra su verdadero poder cuando se apoya en un plan sólido. Diseña el desafío de mañana con calma y conserva tu energía.' },
      { ko: '무난한 하루가 예상되지만, 방심은 금물입니다. 기본에 충실할 때 좋은 흐름이 유지되는 것처럼, 사소한 루틴 하나하나가 결국 큰 성과를 지탱하는 토대가 됩니다. 평범해 보이는 오늘을 내일의 도약을 위한 조용한 연습으로 삼으세요.', en: 'A smooth day is expected, but don\'t let your guard down. Just as staying true to basics maintains good momentum, each small daily routine ultimately becomes the foundation supporting great results. Treat today\'s ordinary appearance as quiet practice for tomorrow\'s leap.', zh: '预计平稳的一天，但不要掉以轻心。就像忠于基础能保持好势头，每一个小日常都是支撑大成就的基础。把看似平凡的今天作为明天飞跃的安静练习。', ja: '無難な一日が予想されますが油断は禁物です。基本に忠実であれば良い流れが維持されるように、些細なルーティン一つひとつが結局大きな成果を支える土台となります。平凡に見える今日を明日の飛躍のための静かな練習として活用してください。', es: 'Se espera un día tranquilo, pero no bajes la guardia. Así como mantenerse fiel a lo básico mantiene el buen impulso, cada pequeña rutina es la base que sostiene grandes resultados. Trata la apariencia ordinaria de hoy como práctica silenciosa para el salto de mañana.' },
      { ko: '양자리의 에너지를 오늘은 내면으로 향하게 해보세요. 외부로 쏟아내던 불꽃이 안으로 돌아올 때, 자기 성찰이라는 가장 깊은 연료가 채워집니다. 이 시간이 곧 내일 더 크게 타오를 활력의 원천이 됩니다.', en: 'Direct your Aries energy inward today. When the flame you usually pour outward turns inward, the deepest fuel of self-reflection gets replenished. This time becomes the source of vitality that will burn even brighter tomorrow.', zh: '今天将白羊座的能量导向内心。平时向外倾注的火焰转向内在时，自我反省这最深的燃料得以补充。这段时间将成为明天更旺燃烧的活力源泉。', ja: '牡羊座のエネルギーを今日は内面に向けてみてください。外部に注ぎ込んでいた炎が内に向かう時、自己省察という最も深い燃料が補充されます。この時間がすなわち明日さらに大きく燃え上がる活力の源となります。', es: 'Dirige tu energía ariana hacia adentro hoy. Cuando la llama que normalmente viertes hacia afuera se vuelve hacia adentro, el combustible más profundo de la autorreflexión se repone. Este tiempo se convierte en la fuente de vitalidad que arderá aún más brillante mañana.' },
      { ko: '크고 작은 선택의 순간들이 오늘 여러 번 찾아오겠지만, 신중하게 판단하면 무리 없이 넘어갑니다. 선택이란 방향이고, 방향이 쌓이면 결국 목적지가 됩니다. 오늘의 작은 결정들을 가볍게 여기지 말고 하나하나 의미 있게 내려보세요.', en: 'Various big and small choice moments will come today, but careful judgment will get you through each one smoothly. Choices are directions, and accumulated directions eventually become a destination. Don\'t take today\'s small decisions lightly—make each one meaningfully.', zh: '今天会有多次大大小小的选择时刻，谨慎判断就能顺利度过。选择就是方向，方向积累最终成为目的地。不要轻视今天的小决定，一个一个认真地做出。', ja: '大小さまざまな選択の瞬間が今日何度も訪れますが、慎重に判断すれば無理なく乗り越えられます。選択とは方向であり、方向が積み重なればやがて目的地となります。今日の小さな決定を軽く見ずに一つひとつ意味を持って下してみてください。', es: 'Varios momentos de elección grandes y pequeños llegarán hoy, pero el juicio cuidadoso te llevará a través de cada uno sin problemas. Las elecciones son direcciones, y las direcciones acumuladas eventualmente se convierten en un destino. No tomes a la ligera las pequeñas decisiones de hoy—toma cada una con significado.' },
      { ko: '오늘은 혼자 돌진하기보다 주변의 의견에 귀를 기울여보세요. 협력은 양자리의 불꽃을 더 크게 키우는 산소와 같아서, 혼자 달릴 때보다 훨씬 나은 결과를 만들어냅니다. 오늘 들은 아이디어 중 하나를 내일의 행동으로 연결해보세요.', en: 'Listen to others\' opinions today instead of charging ahead alone. Collaboration is like oxygen that makes the Aries flame grow larger—it creates far better results than running solo. Connect one idea you hear today to action tomorrow.', zh: '今天不要独自冲锋，而是倾听周围的意见。合作就像让白羊座火焰燃烧更旺的氧气，能创造比独自奔跑更好的结果。把今天听到的一个想法与明天的行动联系起来。', ja: '今日は一人で突進するより周りの意見に耳を傾けてみてください。協力は牡羊座の炎をより大きく育てる酸素のようなもので、一人で走る時よりずっと良い結果を生みます。今日聞いたアイデアの一つを明日の行動につなげてみてください。', es: 'Escucha las opiniones de otros hoy en lugar de avanzar solo. La colaboración es como el oxígeno que hace crecer más la llama ariana—crea resultados mucho mejores que correr en solitario. Conecta una idea que escuches hoy con una acción para mañana.' },
      { ko: '일상적인 루틴 속에서 체력 관리에 신경 쓰면 컨디션이 한층 좋아집니다. 양자리의 화성 에너지는 몸이 준비되어 있을 때 가장 효율적으로 작동하기 때문에, 오늘의 몸 상태가 내일의 성과를 결정합니다. 작은 습관 하나를 지키는 것이 곧 경쟁력입니다.', en: 'Focusing on physical care in your daily routine significantly boosts your condition. Mars energy works most efficiently when the body is prepared, so today\'s physical state determines tomorrow\'s performance. Keeping even one small habit is your competitive edge.', zh: '在日常中注意体力管理，状态会大幅改善。白羊座的火星能量在身体准备就绪时最高效地运作，所以今天的身体状态决定明天的成果。坚守一个小习惯就是竞争力。', ja: '日常のルーティンの中で体力管理に気を配ればコンディションが一段と良くなります。牡羊座の火星エネルギーは体が準備できている時に最も効率的に働くので今日の体調が明日の成果を決めます。小さな習慣一つを守ることがすなわち競争力になります。', es: 'Enfocarte en el cuidado físico en tu rutina diaria mejora significativamente tu condición. La energía de Marte funciona más eficientemente cuando el cuerpo está preparado, así que el estado físico de hoy determina el rendimiento de mañana. Mantener incluso un pequeño hábito es tu ventaja competitiva.' },
      { ko: '특별한 이벤트 없이 조용한 하루지만, 이런 날들의 축적이 결국 큰 성과의 밑거름이 됩니다. 씨앗이 땅 속에서 자라는 동안 겉으로는 아무것도 보이지 않지만, 그 시간이 없다면 꽃도 없습니다. 오늘의 평범한 노력이 내일의 폭발적 성장을 준비하고 있습니다.', en: 'A quiet day without special events, but the accumulation of these days ultimately becomes the soil for great achievements. While a seed grows underground, nothing is visible on the surface—yet without that time, there would be no flower. Today\'s ordinary effort is preparing tomorrow\'s explosive growth.', zh: '没有特别事件的安静一天，但这样日子的积累最终成为大成就的土壤。种子在地下生长时表面什么都看不见，但没有那段时间就没有花朵。今天平凡的努力正在为明天的爆发性成长做准备。', ja: '特別なイベントのない静かな一日ですが、こんな日の積み重ねが結局大きな成果の礎となります。種が地中で育つ間表面には何も見えませんが、その時間がなければ花もありません。今日の平凡な努力が明日の爆発的成長を準備しています。', es: 'Un día tranquilo sin eventos especiales, pero la acumulación de estos días se convierte en la tierra fértil de grandes logros. Mientras una semilla crece bajo tierra, nada es visible en la superficie—sin ese tiempo, no habría flor. El esfuerzo ordinario de hoy está preparando el crecimiento explosivo de mañana.' },
    ],
    low: [
      { ko: '충동적인 결정을 조심해야 하는 날입니다. 화성의 에너지가 때로는 생각보다 빠르게 손을 움직이게 만들기 때문입니다. 오늘은 한 발 물러서서 상황을 관찰하는 지혜를 선택하면, 내일 더 유리한 자리에서 행동할 수 있습니다.', en: 'Be careful of impulsive decisions today. Mars\' energy sometimes moves your hands faster than your thoughts. Choose the wisdom of stepping back and observing today, and tomorrow you can act from a far more advantageous position.', zh: '今天要小心冲动的决定。火星的能量有时让你的手比思想动得更快。今天选择退一步观察情况的智慧，明天就能从更有利的位置行动。', ja: '衝動的な決定に気をつけるべき日です。火星のエネルギーが時に思考より早く手を動かしてしまうからです。今日は一歩引いて状況を観察する知恵を選べば、明日より有利な立場で行動できます。', es: 'Ten cuidado con las decisiones impulsivas hoy. La energía de Marte a veces mueve tus manos más rápido que tus pensamientos. Elige la sabiduría de retroceder y observar hoy, y mañana podrás actuar desde una posición mucho más ventajosa.' },
      { ko: '화성의 에너지가 과열되어 갈등이 생기기 쉬운 날입니다. 당신의 직접적인 소통 방식은 강점이지만, 오늘만큼은 말 대신 심호흡이 더 강력한 무기가 될 수 있습니다. 감정적 반응을 자제하면 오히려 더 큰 존중을 얻게 됩니다.', en: 'Mars\' energy overheats today, making conflicts likely. Your direct communication style is a strength, but today a deep breath can be a more powerful weapon than words. Controlling emotional reactions will actually earn you greater respect.', zh: '火星能量过热，今天容易产生冲突。你直接的沟通方式是优势，但今天深呼吸可能比言语更有力。控制情绪反应，反而能获得更大的尊重。', ja: '火星のエネルギーが過熱して葛藤が生じやすい日です。あなたの直接的なコミュニケーションスタイルは強みですが、今日だけは言葉より深呼吸の方が強力な武器になり得ます。感情的な反応を抑えることでむしろより大きな敬意を得られます。', es: 'La energía de Marte se sobrecalienta hoy, haciendo probables los conflictos. Tu estilo de comunicación directa es una fortaleza, pero hoy una respiración profunda puede ser un arma más poderosa que las palabras. Controlar las reacciones emocionales te ganará mayor respeto.' },
      { ko: '무리한 도전보다 현재 진행 중인 일을 마무리하는 데 집중해야 하는 날입니다. 완주가 시작보다 더 값진 이유는, 끝까지 해낸 사람만이 진정한 성취감을 알기 때문입니다. 오늘 하나를 완성하면 내일 새로운 불꽃이 더 강하게 타오릅니다.', en: 'Focus on finishing current tasks rather than reckless new challenges today. Completion is more valuable than starting because only those who finish know true achievement. Complete one thing today and tomorrow a new flame will burn stronger.', zh: '今天应专注完成进行中的事，而非冒险开始新挑战。完成比开始更有价值，因为只有坚持到最后的人才知道真正的成就感。今天完成一件事，明天新的火焰会燃烧得更旺。', ja: '無理な挑戦より現在進行中の仕事を仕上げることに集中すべき日です。完走がスタートよりも価値があるのは、最後までやり遂げた人だけが真の達成感を知るからです。今日一つを完成させれば明日新しい炎がより強く燃え上がります。', es: 'Enfócate en terminar tareas actuales en lugar de nuevos desafíos imprudentes hoy. Completar es más valioso que empezar porque solo quienes terminan conocen el verdadero logro. Completa una cosa hoy y mañana una nueva llama arderá más fuerte.' },
      { ko: '성급한 판단이 예상치 못한 문제를 만들 수 있는 날입니다. 화성의 과열된 에너지는 때로 결론으로 너무 빠르게 달려가는 함정을 만들기 때문입니다. 중요한 결정은 내일로 미루고, 오늘은 더 많은 정보를 수집하는 데 시간을 쓰세요.', en: 'Hasty judgment may create unexpected problems today. Mars\' overheated energy sometimes creates the trap of rushing too quickly to conclusions. Postpone important decisions until tomorrow and spend today collecting more information.', zh: '仓促的判断今天可能造成意想不到的问题。火星过热的能量有时会制造过快得出结论的陷阱。把重要决定推迟到明天，今天花时间收集更多信息。', ja: '急いだ判断が予想外の問題を起こす可能性がある日です。火星の過熱したエネルギーが時に結論へ急ぎすぎるという罠を作るからです。重要な決定は明日に延期し今日はより多くの情報を収集することに時間を使ってください。', es: 'El juicio apresurado puede crear problemas inesperados hoy. La energía sobrecalentada de Marte a veces crea la trampa de precipitarse a conclusiones. Pospón decisiones importantes hasta mañana y usa hoy para recopilar más información.' },
      { ko: '에너지 소모가 큰 하루가 될 수 있으니, 무리하지 말고 적절한 휴식을 취하는 것이 중요합니다. 양자리의 불꽃은 연료 없이는 꺼지고, 쉬는 것 자체가 내일을 위한 가장 전략적인 행동임을 기억하세요. 오늘 잘 쉰 당신이 내일 두 배로 달릴 수 있습니다.', en: 'This may be a high-energy-expenditure day, so not pushing too hard and taking proper rest is essential. The Aries flame goes out without fuel, and remember that resting itself is the most strategic action for tomorrow. You who rest well today can run twice as fast tomorrow.', zh: '今天可能是消耗大量能量的一天，重要的是不要勉强，要适当休息。白羊座的火焰没有燃料就会熄灭，记住休息本身就是为明天最有战略意义的行动。今天好好休息的你，明天能跑得快两倍。', ja: 'エネルギー消耗が大きい一日になりそうなので無理せず適切な休息を取ることが大切です。牡羊座の炎は燃料なしでは消えてしまい、休むこと自体が明日のための最も戦略的な行動であることを覚えておいてください。今日よく休んだあなたが明日倍の速さで走れます。', es: 'Este puede ser un día de alto gasto energético, así que es esencial no exigirse demasiado y tomar descanso adecuado. La llama ariana se apaga sin combustible, y recuerda que descansar en sí mismo es la acción más estratégica para mañana. Tú que descansas bien hoy puedes correr el doble de rápido mañana.' },
      { ko: '주변 사람들과의 마찰에 주의해야 하는 날입니다. 양자리의 직설적인 말투는 진실을 말하는 용기이지만, 오늘은 그 진실이 상대방이 받아들일 준비가 된 방식으로 전달되어야 합니다. 강함은 부드러움을 통해 더 멀리 닿습니다.', en: 'Watch for friction with others today. Your Aries directness is the courage to speak truth, but today that truth needs to be delivered in a way the other person is ready to receive. Strength reaches further when delivered through softness.', zh: '今天要注意与周围人的摩擦。白羊座的直率是说真话的勇气，但今天那个真相需要以对方准备好接受的方式传达。力量通过柔和传递得更远。', ja: '周りの人との摩擦に注意すべき日です。牡羊座の直接的な言い方は真実を語る勇気ですが、今日はその真実が相手が受け取れる準備ができた方法で伝える必要があります。強さは柔らかさを通してより遠くに届きます。', es: 'Presta atención a las fricciones con otros hoy. Tu franqueza ariana es el valor de hablar la verdad, pero hoy esa verdad necesita entregarse de una manera que la otra persona esté lista para recibir. La fuerza llega más lejos cuando se entrega con suavidad.' },
      { ko: '과도한 자신감이 실수를 부를 수 있는 날입니다. 양자리의 자신감은 최대 강점이지만, 오늘만큼은 겸손이라는 보호막이 더 필요합니다. 모든 것을 안다고 가정하는 순간부터 배움이 멈추기 때문에, 열린 자세로 하루를 마주하세요.', en: 'Excess confidence could lead to mistakes today. Aries confidence is your greatest strength, but today you need the shield of humility more. The moment you assume you know everything, learning stops—so face the day with an open posture.', zh: '过度自信今天可能导致失误。白羊座的自信是最大优势，但今天更需要谦逊这层保护。因为从认为自己无所不知的那一刻起学习就停止了，所以以开放的姿态迎接今天。', ja: '過度な自信がミスを招く可能性がある日です。牡羊座の自信は最大の強みですが、今日だけは謙虚さという盾がより必要です。全てを知っていると仮定した瞬間から学びが止まるので、オープンな姿勢で一日を迎えてください。', es: 'El exceso de confianza podría causar errores hoy. La confianza ariana es tu mayor fortaleza, pero hoy necesitas más el escudo de la humildad. En el momento en que asumes que lo sabes todo, el aprendizaje se detiene—así que enfrenta el día con una postura abierta.' },
      { ko: '몸과 마음의 과열 신호에 귀를 기울여야 할 날입니다. 화성의 에너지가 넘쳐도 용기가 되지만, 과부하가 걸리면 오히려 전진을 막는 장벽이 됩니다. 오늘은 전투 모드 대신 회복 모드를 선택하는 것이 내일의 더 큰 승리를 준비하는 길입니다.', en: 'Listen carefully to signs of overheating in body and mind today. Mars\' overflow of energy can become courage, but when overloaded it becomes a barrier blocking progress instead. Choosing recovery mode over battle mode today is the path to preparing tomorrow\'s greater victory.', zh: '今天要倾听身心过热的信号。火星能量溢出时是勇气，但过载时反而成为阻碍前进的障碍。今天选择恢复模式而非战斗模式，是准备明天更大胜利的道路。', ja: '体と心の過熱サインに耳を傾けるべき日です。火星のエネルギーが溢れても勇気になりますが過負荷になるとかえって前進を妨げる壁になります。今日は戦闘モードの代わりに回復モードを選ぶことが明日のより大きな勝利を準備する道です。', es: 'Escucha atentamente las señales de sobrecalentamiento en cuerpo y mente hoy. El desbordamiento de energía de Marte puede convertirse en valor, pero cuando se sobrecarga se convierte en una barrera que bloquea el progreso. Elegir el modo recuperación sobre el modo batalla hoy es el camino para preparar la mayor victoria de mañana.' },
      { ko: '새로운 시작보다 기존의 관계와 약속을 돌보는 데 에너지를 쓰는 것이 현명합니다. 가장 탄탄한 도약은 흔들리지 않는 기반 위에서만 가능하기 때문에, 기반이 약해진 지금 그것을 돌보는 것이 곧 미래를 짓는 일입니다. 오늘 연락하지 못했던 중요한 사람에게 먼저 손을 내밀어보세요.', en: 'Spend your energy nurturing existing relationships and commitments rather than new beginnings today. The most solid leap is only possible on an unshakeable foundation—so tending to it when it weakens is actually building your future. Reach out first today to an important person you haven\'t connected with.', zh: '今天把能量花在维护现有关系和承诺上，而非新的开始更为明智。最稳健的跃进只有在坚实的基础上才能实现，所以基础动摇时照顾它就是在建设未来。今天主动向一个许久没有联系的重要人伸出手。', ja: '新しい始まりより既存の関係と約束を大切にするためにエネルギーを使うのが賢明です。最も確固とした飛躍は揺るぎない基盤の上でのみ可能なので基盤が弱まった今それを大切にすることがすなわち未来を築くことです。今日連絡できていなかった大切な人に先に手を伸ばしてみてください。', es: 'Gasta tu energía en nutrir relaciones y compromisos existentes en lugar de nuevos comienzos hoy. El salto más sólido solo es posible sobre una base inamovible—así que cuidarla cuando se debilita es en realidad construir tu futuro. Extiende la mano primero hoy a alguien importante con quien no te has conectado.' },
      { ko: '경쟁심에 불이 붙기 쉬운 날이므로, 승부욕을 잠시 내려놓고 평화로운 하루를 의식적으로 선택해보세요. 이기고 싶은 충동은 강점이지만, 모든 순간에 불꽃을 피우면 결국 연료가 바닥납니다. 오늘의 평화는 내일의 더 날카로운 집중력을 위한 충전입니다.', en: 'Competition fires up easily today, so consciously choose to set aside your competitive drive and select a peaceful day. The urge to win is a strength, but igniting the flame at every moment eventually runs out of fuel. Today\'s peace is the recharge for tomorrow\'s sharper focus.', zh: '今天竞争心容易被点燃，所以有意识地选择暂时放下胜负欲，选择平和的一天。想赢的冲动是优势，但每时每刻都点火最终会耗尽燃料。今天的平和是为明天更犀利专注力的充电。', ja: '競争心に火がつきやすい日なので、勝負欲を一旦下ろして平和な一日を意識的に選んでみてください。勝ちたい衝動は強みですが、あらゆる瞬間に炎を燃やせば結局燃料が尽きてしまいます。今日の平和は明日のより鋭い集中力のための充電です。', es: 'La competitividad se enciende fácilmente hoy, así que elige conscientemente dejar de lado tu impulso competitivo y seleccionar un día pacífico. El impulso de ganar es una fortaleza, pero encender la llama en cada momento eventualmente agota el combustible. La paz de hoy es la recarga para el enfoque más agudo de mañana.' },
    ],
  },
  love: {
    high: [
      { ko: '화성의 열정적 에너지가 오늘 사랑에 강렬한 불꽃을 피웁니다. 당신의 진심은 이미 상대의 마음 문 앞에 서 있으니, 두드리는 용기만 있으면 됩니다. 지금 고백하면 반드시 좋은 반응이 돌아올 것입니다.', en: 'Mars\' passionate energy ignites an intense flame in love today. Your sincerity is already standing at the door of their heart—you only need the courage to knock. Confess now and a good response will surely come back to you.', zh: '火星的热情能量今天在爱情中点燃强烈的火花。你的真心已经站在对方心门前，只需要敲门的勇气。现在告白，必定会有好的回应。', ja: '火星の情熱的なエネルギーが今日恋に強烈な火花を散らします。あなたの真心はすでに相手の心の扉の前に立っているので、叩く勇気さえあればいいのです。今告白すれば必ず良い反応が返ってくるでしょう。', es: 'La energía apasionada de Marte enciende una llama intensa en el amor hoy. Tu sinceridad ya está parada ante la puerta de su corazón—solo necesitas el valor de llamar. Confiésate ahora y una buena respuesta seguramente te llegará.' },
      { ko: '양자리의 적극적인 매력이 오늘 완전한 최고조에 달합니다. 당신이 의식하지 않아도 자연스럽게 이성의 시선을 끌 만큼 오늘의 존재감은 압도적입니다. 이 에너지를 낭비하지 말고, 마음속에 품어온 그 사람에게 직접 말을 건네보세요.', en: 'Your Aries charm reaches complete peak today. Your presence is so overwhelming that you naturally attract attention without even trying. Don\'t waste this energy—go ahead and speak directly to that person you\'ve been holding in your heart.', zh: '白羊座积极的魅力今天达到完全的最高点。即使你没意识到，你今天的存在感也压倒一切，自然吸引异性目光。不要浪费这股能量，直接向心里一直挂念的那个人开口吧。', ja: '牡羊座の積極的な魅力が今日完全な最高潮に達します。あなたが意識しなくても自然と異性の視線を引くほど今日の存在感は圧倒的です。このエネルギーを無駄にせず心の中で思い続けてきたあの人に直接声をかけてみてください。', es: 'Tu encanto ariano alcanza su pico completo hoy. Tu presencia es tan abrumadora que naturalmente atraes atención sin siquiera intentarlo. No desperdicies esta energía—ve y habla directamente a esa persona que has llevado en tu corazón.' },
      { ko: '연인과의 관계가 한층 깊어지는 특별한 시간이 찾아왔습니다. 함께 처음 해보는 활동을 시도할 때, 공유된 설렘이 두 사람 사이에 새로운 기억을 새깁니다. 오늘 계획한 한 가지 새로운 경험이 오랫동안 이야기할 추억이 됩니다.', en: 'A special time arrives when your relationship deepens significantly. When you try a new activity together for the first time, shared excitement carves new memories between you two. One new experience you plan today becomes a story you\'ll tell for a long time.', zh: '关系进一步加深的特别时刻来临。一起尝试第一次做的活动时，共享的兴奋在两人之间刻下新的记忆。今天计划的一个新体验会成为长久谈起的回忆。', ja: '恋人との関係が一段と深まる特別な時間が訪れました。一緒に初めてやる活動を試みる時、共有された胸のときめきが二人の間に新しい記憶を刻みます。今日計画した一つの新しい経験が長い間語り続ける思い出になります。', es: 'Un momento especial llega cuando tu relación se profundiza significativamente. Cuando intentan una actividad nueva juntos por primera vez, la emoción compartida graba nuevos recuerdos entre ustedes. Una nueva experiencia que planees hoy se convierte en una historia que contarás por mucho tiempo.' },
      { ko: '솔로라면 활동적인 모임에서 운명적 만남이 기다리고 있습니다. 집에 있으면 기회가 당신을 찾아올 수 없습니다. 오늘 밖으로 나가서 당신의 에너지를 세상에 드러내면, 우주가 그에 화답하는 사람을 보내줄 것입니다.', en: 'If single, a fateful encounter awaits at active gatherings. Opportunities cannot come find you if you stay home. Go out today and reveal your energy to the world, and the universe will send someone who responds in kind.', zh: '如果单身，在活跃的聚会中有命运般的邂逅等着你。如果待在家里，机会就无法找到你。今天出去，向世界展现你的能量，宇宙会送来与之呼应的人。', ja: 'シングルなら活動的な集まりで運命的な出会いが待っています。家にいれば機会があなたを見つけに来ることができません。今日外に出てあなたのエネルギーを世界に現せば、宇宙がそれに応える人を送ってくれるでしょう。', es: 'Si estás soltero/a, un encuentro fatídico te espera en reuniones activas. Las oportunidades no pueden venir a buscarte si te quedas en casa. Sal hoy y revela tu energía al mundo, y el universo enviará a alguien que responda del mismo modo.' },
      { ko: '오늘 당신의 솔직한 감정 표현이 상대의 마음을 크게 움직입니다. 양자리는 가식 없이 진심을 드러낼 때 가장 아름다운 별자리이기 때문입니다. 오늘 그 진심을 말이나 작은 행동으로 보여주면, 상대는 그것을 오래 기억합니다.', en: 'Your honest emotional expression deeply moves them today. Aries is most beautiful when revealing genuine feelings without pretense. Show that sincerity through words or a small action today, and they will remember it for a long time.', zh: '今天你坦率的情感表达会大大打动对方。白羊座是在没有做作地展现真心时最美丽的星座。今天用言语或小行动展示那份真心，对方会长久地记住。', ja: '今日あなたの素直な感情表現が相手の心を大きく動かします。牡羊座は虚飾なく真心を現す時に最も美しい星座だからです。今日その真心を言葉や小さな行動で見せれば、相手はそれを長く覚えています。', es: 'Tu expresión emocional honesta los conmueve profundamente hoy. Aries es más hermoso cuando revela sentimientos genuinos sin pretensión. Muestra esa sinceridad a través de palabras o una pequeña acción hoy, y lo recordarán por mucho tiempo.' },
      { ko: '불꽃 같은 로맨스의 기운이 오늘 강하게 감돌고 있습니다. 서프라이즈는 상대방이 예측하지 못할 때 가장 깊은 감동을 주는 법입니다. 오늘 작은 이벤트 하나를 계획하면, 두 사람의 관계에 영원히 남을 특별한 순간이 만들어집니다.', en: 'A blazing romantic energy fills the air strongly today. Surprises create the deepest impact when the other person least expects them. Plan one small event today and you\'ll create a special moment that stays in your relationship forever.', zh: '如火焰般的浪漫气息今天强烈弥漫。惊喜在对方意想不到时带来最深的感动。今天策划一个小惊喜，就能创造永远留在两人关系中的特别瞬间。', ja: '炎のようなロマンスの気運が今日強く漂っています。サプライズは相手が予測できない時に最も深い感動を与えるものです。今日小さなイベントを一つ計画すれば、二人の関係に永遠に残る特別な瞬間が生まれます。', es: 'Una ardiente energía romántica llena el aire fuertemente hoy. Las sorpresas crean el impacto más profundo cuando la otra persona menos lo espera. Planea un pequeño evento hoy y crearás un momento especial que quedará en tu relación para siempre.' },
      { ko: '화성이 금성과 아름다운 조화를 이루어, 오늘 사랑과 열정이 완벽하게 균형 잡힌 하루입니다. 밀어붙이는 힘과 받아들이는 따뜻함이 동시에 발동되어, 당신의 사랑은 오늘 가장 완성된 형태로 빛납니다. 이 특별한 날, 사랑하는 사람과 함께 있으세요.', en: 'Mars harmonizes beautifully with Venus today—love and passion are perfectly balanced. The force that pushes and the warmth that receives are activated simultaneously, making your love shine in its most complete form today. Spend this special day with the person you love.', zh: '火星与金星今天美好地和谐，爱情与热情完美平衡。推进的力量与接纳的温暖同时启动，你的爱今天以最完整的形态闪耀。在这特别的一天，与你爱的人在一起。', ja: '火星が金星と美しく調和して、今日は愛と情熱が完璧にバランスの取れた一日です。押し進める力と受け入れる温かさが同時に作動して、あなたの愛は今日最も完成した形で輝きます。この特別な日、愛する人と一緒にいてください。', es: 'Marte se armoniza hermosamente con Venus hoy—amor y pasión están perfectamente equilibrados. La fuerza que empuja y la calidez que recibe se activan simultáneamente, haciendo brillar tu amor en su forma más completa hoy. Pasa este día especial con la persona que amas.' },
      { ko: '용기 있는 한마디가 관계를 완전히 새로운 단계로 발전시키는 날입니다. 말하지 않으면 상대방은 영원히 모를 수도 있습니다. 두려움을 직면하고 그 한마디를 내뱉는 순간, 당신의 관계는 새로운 챕터를 시작합니다.', en: 'One brave word elevates your relationship to a completely new level today. If you don\'t say it, they may never know. The moment you face the fear and speak those words, your relationship begins a new chapter.', zh: '勇敢的一句话今天将关系提升到全新阶段。如果你不说，对方可能永远不会知道。直面恐惧说出那句话的瞬间，你们的关系开始新的篇章。', ja: '勇気ある一言が関係を全く新しい段階に発展させる日です。言わなければ相手は永遠に知らないままかもしれません。恐れに向き合ってその一言を口にする瞬間、あなたの関係は新しいチャプターを始めます。', es: 'Una palabra valiente eleva tu relación a un nivel completamente nuevo hoy. Si no lo dices, quizás nunca lo sabrán. El momento en que enfrentas el miedo y pronuncias esas palabras, tu relación comienza un nuevo capítulo.' },
      { ko: '함께하는 모험이 둘 사이의 유대감을 강화하는 날입니다. 일상의 틀을 벗어난 경험이 관계에 산소를 공급하는 것처럼, 새로운 것을 함께 시도할 때 두 사람은 더 강한 팀이 됩니다. 오늘 액티비티 데이트를 계획해 둘만의 새로운 이야기를 만들어가세요.', en: 'Shared adventure strengthens your bond today. Just as experiences outside the daily frame supply oxygen to a relationship, trying something new together makes you a stronger team. Plan an activity date today and create a new story that belongs only to the two of you.', zh: '共同的冒险今天增强两人之间的纽带。就像脱离日常框架的体验为关系提供氧气，一起尝试新事物让两人成为更强的团队。今天计划一个活动约会，创造属于两人的新故事。', ja: '一緒の冒険が二人の絆を強化する日です。日常の枠を外れた経験が関係に酸素を供給するように、新しいことを一緒に試みる時二人はより強いチームになります。今日アクティビティデートを計画して二人だけの新しい物語を作っていってください。', es: 'La aventura compartida fortalece su vínculo hoy. Así como las experiencias fuera del marco cotidiano suministran oxígeno a una relación, intentar algo nuevo juntos los convierte en un equipo más fuerte. Planea una cita activa hoy y crea una nueva historia que pertenezca solo a los dos.' },
      { ko: '당신의 보호적이고 헌신적인 모습이 파트너에게 깊은 감동을 주는 날입니다. 사람들은 대체로 사랑받는다는 것을 머리로는 알아도 가슴으로 느끼고 싶어 하기 때문에, 말이 아닌 행동으로 그 마음을 표현하는 것이 오늘 가장 강력한 사랑의 언어입니다.', en: 'Your protective devotion deeply moves your partner today. People generally know they are loved in their minds but want to feel it in their hearts—so expressing that feeling through actions rather than words is the most powerful language of love today.', zh: '你保护性和奉献的一面今天深深感动了伴侣。人们通常头脑上知道被爱着，但想在心里感受到它，所以今天用行动而非言语表达那份心意，是最有力的爱的语言。', ja: 'あなたの保護的で献身的な姿がパートナーに深い感動を与える日です。人々は概して愛されていることを頭では分かっていても心で感じたいと思うので言葉でなく行動でその気持ちを表現することが今日最も強力な愛の言語です。', es: 'Tu devoción protectora conmueve profundamente a tu pareja hoy. La gente generalmente sabe que es amada en su mente pero quiere sentirlo en su corazón—así que expresar ese sentimiento a través de acciones en lugar de palabras es el lenguaje de amor más poderoso hoy.' },
    ],
    medium: [
      { ko: '사랑에서도 서두르지 마세요. 양자리의 빠른 본능이 때로는 감정의 성숙보다 앞서 달리기 때문입니다. 자연스러운 흐름을 따를 때 당신에게 진정으로 맞는 인연이 적절한 시기에 다가옵니다.', en: 'Don\'t rush in love either. Your Aries instinct sometimes runs ahead of emotional maturity. When you follow the natural flow, the connection that truly fits you arrives at the right time.', zh: '爱情中也不要着急。白羊座的快速本能有时超前于情感的成熟。顺其自然时，真正适合你的缘分会在恰当的时机到来。', ja: '恋愛でも焦らないでください。牡羊座の素早い本能が時に感情の成熟より先に走ってしまうからです。自然な流れに従う時、あなたに真に合う縁が適切な時期に訪れます。', es: 'No apresures el amor tampoco. Tu instinto ariano a veces corre adelante de la madurez emocional. Cuando sigues el flujo natural, la conexión que verdaderamente te corresponde llega en el momento adecuado.' },
      { ko: '파트너와의 평화로운 일상이 잘 유지되고 있는 날입니다. 화려한 이벤트보다 일상 속 작은 배려가 관계를 더욱 따뜻하게 만들어줍니다. 오늘 상대방이 좋아하는 것 하나를 기억해서 자연스럽게 실천해보세요.', en: 'A peaceful daily life with your partner is well maintained today. Small everyday gestures warm the relationship far more than grand events. Today, remember one thing your partner loves and naturally do it.', zh: '与伴侣平和的日常今天保持得很好。日常中小小的关怀比华丽的活动更能温暖关系。今天记住对方喜欢的一件事，自然地付诸行动。', ja: 'パートナーとの平和な日常がうまく維持されている日です。華やかなイベントより日常の中の小さな配慮が関係をより温かくしてくれます。今日相手が好きなものを一つ覚えて自然に実践してみてください。', es: 'La vida diaria pacífica con tu pareja se mantiene bien hoy. Los pequeños gestos cotidianos calientan la relación mucho más que los grandes eventos. Hoy, recuerda algo que tu pareja ama y hazlo de forma natural.' },
      { ko: '연애보다 자기 자신에게 집중하는 시간이 오늘은 필요합니다. 완전한 자신을 채웠을 때 비로소 진정한 사랑을 나눌 수 있기 때문에, 혼자만의 시간은 낭비가 아닌 준비입니다. 오늘의 충전이 내일의 더 따뜻한 사랑을 만들어냅니다.', en: 'You need time focused on yourself rather than romance today. Only when you\'ve fully filled yourself can you share true love—so alone time is not a waste but preparation. Today\'s recharging creates tomorrow\'s warmer love.', zh: '今天需要把注意力放在自己而非恋爱上。只有充实了自己才能分享真正的爱，所以独处时光不是浪费而是准备。今天的充电创造明天更温暖的爱。', ja: '恋愛より自分自身に集中する時間が今日は必要です。完全な自分を満たした時こそ真の愛を分かち合えるので、一人の時間は無駄ではなく準備です。今日の充電が明日のより温かい愛を生み出します。', es: 'Necesitas tiempo enfocado en ti mismo/a en lugar del romance hoy. Solo cuando te has llenado completamente puedes compartir el amor verdadero—así que el tiempo a solas no es un desperdicio sino una preparación. La recarga de hoy crea el amor más cálido de mañana.' },
      { ko: '급격한 감정 변화보다 차분한 대화가 관계에 훨씬 더 도움이 됩니다. 양자리의 직선적 본능이 때로는 상대방의 말을 미처 다 듣기 전에 반응하게 만드는 경향이 있기 때문입니다. 경청의 자세를 취할 때, 당신은 사랑에서 더 강해집니다.', en: 'Calm conversation helps the relationship far more than sudden emotional swings. Your Aries linear instinct sometimes tends to react before fully hearing the other person. When you practice listening, you become stronger in love.', zh: '平静的对话比突然的情绪波动更有助于关系。白羊座的直线本能有时在听完对方说话前就做出反应。当你保持倾听的姿态时，你在爱情中会变得更强。', ja: '急激な感情の変化より穏やかな対話が関係にずっと役立ちます。牡羊座の直線的な本能が時に相手の言葉を最後まで聞く前に反応してしまう傾向があるからです。傾聴の姿勢を取る時、あなたは愛においてより強くなります。', es: 'La conversación calmada ayuda a la relación mucho más que los bruscos cambios emocionales. Tu instinto lineal ariano a veces tiende a reaccionar antes de escuchar completamente a la otra persona. Cuando practicas la escucha, te vuelves más fuerte en el amor.' },
      { ko: '오늘은 큰 고백보다 일상 속 스킨십과 다정한 말 한마디가 훨씬 더 큰 효과를 냅니다. 사랑은 특별한 날의 이벤트가 아니라 매일의 작은 선택들이 쌓여 만들어지기 때문입니다. 오늘 상대방에게 건네는 진심 담은 한마디가 관계의 온도를 높입니다.', en: 'Small everyday affection and kind words work far better than grand confessions today. Love is built not from special occasion events but from accumulating small daily choices. One heartfelt word you give your partner today raises the temperature of your relationship.', zh: '今天日常的亲密接触和温柔的一句话比大告白更有效。爱情不是由特别日子的活动，而是由每天积累的小选择构建的。今天对对方说的一句真心话，能提升关系的温度。', ja: '今日は大告白より日常のスキンシップと優しい一言の方がずっと大きな効果を発揮します。愛は特別な日のイベントではなく毎日の小さな選択が積み重なって作られるからです。今日相手に伝える真心のこもった一言が関係の温度を上げます。', es: 'Las pequeñas muestras de afecto cotidianas y las palabras amables funcionan mucho mejor que las grandes confesiones hoy. El amor se construye no de eventos en días especiales sino de pequeñas elecciones diarias acumuladas. Una palabra sincera que le des a tu pareja hoy sube la temperatura de tu relación.' },
      { ko: '상대방의 관점에서 생각해보는 연습이 필요한 날입니다. 양자리의 선명한 자아는 때로 자신의 시각이 유일한 시각이라고 착각하게 만들기 때문입니다. 공감 능력을 키우면 사랑이 두 배로 깊어진다는 사실을 오늘 확인해보세요.', en: 'You need practice thinking from your partner\'s perspective today. Your clear Aries self sometimes creates the illusion that your view is the only view. Verify today that building empathy deepens love twice over.', zh: '今天需要练习从对方的角度思考。白羊座鲜明的自我有时会让人误以为自己的视角是唯一的视角。今天验证一下，培养共情能力会让爱情加倍深厚。', ja: '相手の視点で考える練習が必要な日です。牡羊座の鮮明な自我が時に自分の視点が唯一の視点だと錯覚させるからです。共感力を育てれば愛が二倍深くなるという事実を今日確認してみてください。', es: 'Necesitas practicar pensar desde la perspectiva de tu pareja hoy. Tu claro yo ariano a veces crea la ilusión de que tu visión es la única visión. Verifica hoy que cultivar la empatía profundiza el amor el doble.' },
      { ko: '연인이 있다면 함께 조용한 시간을 보내며 서로를 재발견하는 기회로 삼아보세요. 매일 보는 사람이지만 충분히 들여다보지 못한 면들이 있고, 그 발견이 관계에 새로운 설렘을 불어넣습니다. 오늘의 조용한 대화가 내일의 더 깊은 유대로 이어집니다.', en: 'If you have a partner, use time together quietly to rediscover each other. Even someone you see every day has sides you haven\'t looked at closely enough, and that discovery breathes new excitement into the relationship. Today\'s quiet conversation leads to tomorrow\'s deeper bond.', zh: '如果有恋人，一起度过安静的时光，把它作为重新发现彼此的机会。即使是每天见到的人，也有没有仔细观察的一面，那种发现为关系注入新的心动。今天的安静对话通向明天更深的纽带。', ja: '恋人がいるなら一緒に静かな時間を過ごしお互いを再発見する機会にしてみてください。毎日会う人でも十分に見つめていない面があり、その発見が関係に新しいときめきを吹き込みます。今日の静かな対話が明日のより深い絆につながります。', es: 'Si tienes pareja, usa el tiempo juntos en silencio para redescubrirse mutuamente. Incluso alguien que ves todos los días tiene aspectos que no has mirado de cerca lo suficiente, y ese descubrimiento insufla nueva emoción en la relación. La conversación silenciosa de hoy lleva al vínculo más profundo de mañana.' },
      { ko: '새로운 만남에 대한 기대보다 기존 인연을 소중히 여기면 사랑운이 상승합니다. 씨앗을 심고 물을 주지 않으면 결국 시들듯, 관계도 지속적인 관심과 정성이 있어야 꽃이 핍니다. 오늘 그 소중한 인연에 따뜻한 연락 한 통을 드려보세요.', en: 'Valuing existing bonds over expectations of new encounters lifts your love luck. Just as a planted seed wilts without water, relationships need continuous attention and care to bloom. Send a warm message today to that precious connection.', zh: '比起期待新的邂逅，珍惜现有的缘分爱情运会上升。就像播下的种子不浇水最终会枯萎，关系也需要持续的关注和用心才能开花。今天给那段珍贵的缘分发一条温暖的信息。', ja: '新しい出会いへの期待より既存の縁を大切にすれば恋愛運が上昇します。種を植えて水をやらなければ結局しおれるように、関係も継続的な関心と誠意がなければ花が咲きません。今日その大切な縁に温かい連絡を一つ入れてみてください。', es: 'Valorar los vínculos existentes sobre las expectativas de nuevos encuentros eleva tu suerte amorosa. Así como una semilla plantada se marchita sin agua, las relaciones necesitan atención y cuidado continuos para florecer. Envía un mensaje cálido hoy a esa conexión preciosa.' },
      { ko: '열정적인 표현도 좋지만 오늘은 차분하고 부드러운 접근이 상대의 마음을 더 확실하게 엽니다. 불꽃이 강렬할수록 가까이 다가서기 어려운 법이어서, 오늘만큼은 온기를 선택하면 더 많은 것이 당신에게 가까워집니다. 부드러운 힘이 오늘의 사랑 전략입니다.', en: 'Passion is good, but a calm and gentle approach opens their heart more surely today. The more intense the flame, the harder it is to get close—so choosing warmth today brings more things closer to you. Gentle strength is today\'s love strategy.', zh: '热情的表达也好，但今天冷静温柔的方式更能确实打开对方的心。火焰越强烈，越难靠近，所以今天选择温暖，更多事物会向你靠近。柔和的力量是今天的爱情策略。', ja: '情熱的な表現も良いですが今日は穏やかで柔らかいアプローチが相手の心をより確実に開きます。炎が強烈なほど近づきにくいので今日だけは温かさを選べばより多くのものがあなたに近づいてきます。穏やかな力が今日の愛情戦略です。', es: 'La pasión está bien, pero un enfoque calmado y gentil abre su corazón más seguramente hoy. Cuanto más intensa la llama, más difícil es acercarse—así que elegir calidez hoy acerca más cosas a ti. La fuerza gentil es la estrategia de amor de hoy.' },
      { ko: '사랑에 있어 인내심이 시험받는 날일 수 있지만, 기다림은 반드시 보답받습니다. 감정이 격해질 때 오히려 한 발 물러서는 것이 관계에서 가장 성숙한 모습이기 때문입니다. 오늘 인내한 그 마음이 내일 더 깊은 신뢰를 쌓는 기반이 됩니다.', en: 'Your patience in love may be tested today, but waiting will surely be rewarded. Stepping back when emotions run high is actually the most mature response in a relationship. The patience you show today becomes the foundation building deeper trust tomorrow.', zh: '今天爱情中的耐心可能受到考验，但等待必定得到回报。情绪激动时退一步反而是关系中最成熟的表现。今天忍耐的那颗心，成为明天积累更深信任的基础。', ja: '恋愛における忍耐心が試される日かもしれませんが、待つことは必ず報われます。感情が高ぶる時にむしろ一歩引くことが関係において最も成熟した姿だからです。今日忍耐したその気持ちが明日より深い信頼を築く基盤になります。', es: 'Tu paciencia en el amor puede ser probada hoy, pero esperar seguramente será recompensado. Retroceder cuando las emociones se intensifican es en realidad la respuesta más madura en una relación. La paciencia que muestras hoy se convierte en la base que construye una confianza más profunda mañana.' },
    ],
    low: [
      { ko: '질투심이나 독점욕이 관계를 해칠 수 있는 날입니다. 불안에서 비롯된 집착은 사랑처럼 느껴지지만 상대방에게는 압박으로 전달됩니다. 오늘 상대의 자유를 존중하는 선택이 오히려 관계를 더 단단하게 묶는 힘이 됩니다.', en: 'Jealousy or possessiveness could harm your relationship today. Attachment born from insecurity feels like love but is received as pressure. Choosing to respect their freedom today actually becomes the force that binds the relationship more firmly.', zh: '今天嫉妒心或占有欲可能伤害关系。源于不安全感的执着感觉像爱，但传达给对方的是压力。今天选择尊重对方的自由，反而成为更牢固地连接关系的力量。', ja: '嫉妬心や独占欲が関係を損なう可能性がある日です。不安から生まれた執着は愛のように感じますが相手にはプレッシャーとして伝わります。今日相手の自由を尊重する選択がむしろ関係をより強固に結びつける力となります。', es: 'Los celos o la posesividad podrían dañar tu relación hoy. El apego nacido de la inseguridad se siente como amor pero se recibe como presión. Elegir respetar su libertad hoy se convierte en la fuerza que une la relación más firmemente.' },
      { ko: '충동적인 고백이나 이별 선언은 오늘 반드시 후회를 부릅니다. 화성의 과열된 에너지가 감정을 실제보다 더 크게 느끼게 만들기 때문에, 지금 느끼는 것이 전부가 아닐 수 있습니다. 감정이 가라앉은 후 판단해도 늦지 않습니다.', en: 'Impulsive confessions or breakup declarations will surely bring regret today. Mars\' overheated energy makes emotions feel larger than they are, so what you feel now may not be everything. It\'s not too late to judge after emotions settle.', zh: '今天冲动的告白或分手宣言必定带来后悔。火星过热的能量让情绪感觉比实际更大，所以现在感受到的可能不是全部。情绪平静后再判断也不迟。', ja: '衝動的な告白や別れの宣言は今日必ず後悔を招きます。火星の過熱したエネルギーが感情を実際より大きく感じさせるので今感じていることが全てではないかもしれません。感情が落ち着いてから判断しても遅くはありません。', es: 'Las confesiones impulsivas o declaraciones de ruptura traerán arrepentimiento hoy con seguridad. La energía sobrecalentada de Marte hace que las emociones se sientan más grandes de lo que son, así que lo que sientes ahora puede no ser todo. No es tarde para juzgar después de que las emociones se calmen.' },
      { ko: '사소한 말다툼이 큰 갈등으로 번질 수 있는 날입니다. 첫 불꽃을 끄는 것이 나중에 불을 잡는 것보다 훨씬 쉽기 때문에, 논쟁이 시작될 기미가 보이면 지금 바로 한 발 물러서는 것이 지혜입니다. 오늘의 양보가 관계를 지킵니다.', en: 'Small arguments could escalate into big conflicts today. Extinguishing the first spark is much easier than containing a fire later—so when you see signs of argument starting, stepping back right now is wisdom. Today\'s concession protects the relationship.', zh: '今天小口角可能升级为大冲突。扑灭第一个火花比后来控制大火容易得多，所以看到争论开始的苗头时，立刻退一步才是智慧。今天的让步保护了关系。', ja: '些細な口論が大きな葛藤に発展する可能性がある日です。最初の火花を消すことが後で火を制するよりずっと簡単なので論争が始まりそうな兆しが見えたら今すぐ一歩引くことが知恵です。今日の譲歩が関係を守ります。', es: 'Las pequeñas discusiones podrían escalar en grandes conflictos hoy. Apagar la primera chispa es mucho más fácil que contener un incendio después—así que cuando veas señales de que una discusión comienza, retroceder ahora mismo es sabiduría. La concesión de hoy protege la relación.' },
      { ko: '화성의 공격적 에너지가 연애에도 영향을 미치는 날입니다. 당신이 내뱉은 날카로운 말은 순간이지만, 상대방에게는 오래 남는 상처가 될 수 있습니다. 오늘은 말하기 전에 세 번 생각하는 것을 원칙으로 삼으세요.', en: 'Mars\' aggressive energy affects romance today as well. Sharp words you say are momentary, but they can become lasting wounds for the other person. Today, make it a rule to think three times before speaking.', zh: '今天火星的攻击性能量也影响恋爱。你说出的尖锐的话转瞬即逝，但对对方可能是久久留下的伤害。今天把说话前想三次作为原则。', ja: '火星の攻撃的なエネルギーが恋愛にも影響する日です。あなたが口にした鋭い言葉は一瞬ですが、相手には長く残る傷となる可能性があります。今日は話す前に三回考えることを原則にしてください。', es: 'La energía agresiva de Marte afecta el romance también hoy. Las palabras hirientes que dices son momentáneas, pero pueden convertirse en heridas duraderas para la otra persona. Hoy, haz una regla de pensar tres veces antes de hablar.' },
      { ko: '자존심 때문에 먼저 사과하지 못하면 관계가 서서히 멀어질 수 있습니다. 양자리의 용기는 싸움에서만이 아니라 사과하는 데서도 빛나야 합니다. 먼저 손을 내미는 사람이 더 강한 사람임을 오늘 기억하세요.', en: 'Pride preventing apology could gradually distance you from each other. Aries courage should shine not just in battles but in apologies too. Remember today that the person who reaches out first is the stronger one.', zh: '因自尊心不能先道歉可能让关系慢慢疏远。白羊座的勇气不只在战斗中，也应在道歉时闪耀。今天记住，先伸出手的人是更强大的人。', ja: 'プライドで先に謝れないと関係が徐々に遠ざかる可能性があります。牡羊座の勇気は戦いだけでなく謝罪においても輝かなければなりません。先に手を伸ばす人がより強い人であることを今日覚えておいてください。', es: 'El orgullo que impide pedir disculpas podría alejarlos gradualmente. El valor ariano debe brillar no solo en batallas sino también en disculpas. Recuerda hoy que la persona que extiende la mano primero es la más fuerte.' },
      { ko: '새로운 만남에 대한 기대가 높지만 오늘은 신중함이 꼭 필요합니다. 첫인상의 화려함에 현혹되기 쉬운 날이어서, 겉모습보다 그 사람이 어떻게 행동하는지 관찰하는 것이 더 중요합니다. 진짜 가치는 항상 시간이 지나야 보입니다.', en: 'High hopes for new encounters today, but caution is truly necessary. It\'s easy to be dazzled by first impressions today, so observing how the person behaves matters more than appearances. Real value always becomes visible only with time.', zh: '今天对新邂逅期望很高，但确实需要谨慎。今天容易被第一印象的华丽所迷惑，所以观察那个人怎么行动比外表更重要。真正的价值总是需要时间才能显现。', ja: '新しい出会いへの期待が高いですが今日は慎重さが本当に必要です。初印象の華やかさに惑わされやすい日なので外見よりその人がどう行動するかを観察することの方が重要です。本当の価値はいつも時間が経ってから見えてきます。', es: 'Altas esperanzas para nuevos encuentros hoy, pero la cautela es verdaderamente necesaria. Es fácil deslumbrarse con las primeras impresiones hoy, así que observar cómo se comporta la persona importa más que las apariencias. El valor real siempre se vuelve visible solo con el tiempo.' },
      { ko: '상대방의 속도를 무시하고 자신의 페이스만 강요하면 갈등이 생깁니다. 양자리의 빠른 속도가 모두에게 편안한 것은 아니며, 관계는 두 사람이 함께 맞추는 리듬 위에서 지속됩니다. 오늘은 상대의 속도에 나를 맞춰보는 연습을 해보세요.', en: 'Ignoring their pace and forcing yours creates conflict. Your Aries speed isn\'t comfortable for everyone, and relationships last on the rhythm that two people align together. Practice today adjusting yourself to their pace.', zh: '忽视对方的节奏只强加自己的步调会产生冲突。白羊座的快速节奏并非对所有人都舒适，关系在两人共同调整的节奏上持续。今天练习把自己调整到对方的节奏。', ja: '相手のペースを無視して自分のペースだけ押し付けると葛藤が生じます。牡羊座の速いペースが全員に快適なわけではなく、関係は二人が一緒に合わせるリズムの上で継続されます。今日は相手のペースに自分を合わせる練習をしてみてください。', es: 'Ignorar su ritmo e imponer el tuyo crea conflicto. Tu velocidad ariana no es cómoda para todos, y las relaciones duran sobre el ritmo que dos personas alinean juntas. Practica hoy ajustarte a su ritmo.' },
      { ko: '감정이 격해지기 쉬운 날입니다. 연인과의 중요한 대화는 두 사람 모두 침착한 다른 날로 미루는 것이 현명합니다. 말은 한 번 나가면 되돌릴 수 없으니, 오늘의 침묵이 내일의 더 나은 대화를 위한 준비임을 기억하세요.', en: 'Emotions flare easily today. It\'s wise to postpone important conversations with your partner to another day when both of you are calm. Words cannot be taken back once spoken, so remember today\'s silence is preparation for tomorrow\'s better conversation.', zh: '今天情绪容易激动。与恋人的重要对话推迟到两人都平静的另一天更明智。话一旦说出就无法收回，记住今天的沉默是为明天更好对话的准备。', ja: '感情が激しくなりやすい日です。恋人との重要な会話は二人ともが落ち着いた別の日に延期するのが賢明です。言葉は一度出たら取り戻せないので今日の沈黙が明日のより良い会話のための準備であることを覚えておいてください。', es: 'Las emociones se inflaman fácilmente hoy. Es sabio posponer conversaciones importantes con tu pareja para otro día cuando ambos estén tranquilos. Las palabras no se pueden recuperar una vez pronunciadas, así que recuerda que el silencio de hoy es preparación para la mejor conversación de mañana.' },
      { ko: '과거의 미련이 현재 관계에 영향을 줄 수 있습니다. 과거는 이미 끝났지만 내면에서 계속 재생되는 이야기가 지금의 관계를 왜곡하고 있을 수 있습니다. 지난 일을 의식적으로 보내주고 현재의 사람과 새로운 이야기를 써 나가세요.', en: 'Past attachments may affect your current relationship. The past has ended, but stories that keep replaying internally may be distorting your current relationship. Consciously release past things and write a new story with the person present.', zh: '对过去的留恋可能影响现在的关系。过去已经结束，但内心不断重播的故事可能扭曲现在的关系。有意识地放下过去，与当下的人书写新故事。', ja: '過去への未練が現在の関係に影響を与える可能性があります。過去はすでに終わっていますが内面で再生し続けている物語が今の関係を歪めている可能性があります。過ぎたことを意識的に手放して今いる人と新しい物語を書いていってください。', es: 'Los apegos pasados pueden afectar tu relación actual. El pasado ha terminado, pero las historias que siguen reproduciéndose internamente pueden estar distorsionando tu relación actual. Suelta conscientemente las cosas pasadas y escribe una nueva historia con la persona presente.' },
      { ko: '혼자만의 기준으로 상대를 평가하지 마세요. 양자리의 강한 자아가 때로는 자신의 방식이 정답이라고 확신하게 만들지만, 관계는 두 사람이 함께 만들어가는 공동 작품입니다. 상대방의 방식도 하나의 옳은 답임을 인정하면 관계가 훨씬 풍요로워집니다.', en: 'Don\'t judge your partner by your standards alone. Your strong Aries self sometimes convinces you your way is the right answer, but a relationship is a joint work made by two people together. Acknowledging that their way is also a valid answer makes the relationship far richer.', zh: '不要用自己的标准评判对方。白羊座强烈的自我有时让你确信自己的方式是正确答案，但关系是两人共同创作的。承认对方的方式也是一种正确答案，关系会丰富得多。', ja: '自分だけの基準で相手を評価しないでください。牡羊座の強い自我が時に自分の方法が正解だと確信させますが関係は二人で一緒に作っていく共同作品です。相手の方法も一つの正しい答えであることを認めれば関係がずっと豊かになります。', es: 'No juzgues a tu pareja solo por tus estándares. Tu fuerte yo ariano a veces te convence de que tu manera es la respuesta correcta, pero una relación es una obra conjunta creada por dos personas. Reconocer que su manera también es una respuesta válida hace la relación mucho más rica.' },
    ],
  },
  career: {
    high: [
      { ko: '리더십을 발휘할 절호의 기회가 오늘 찾아옵니다. 양자리는 선두에 설 때 자신의 진정한 능력을 발휘하는 별자리이기 때문에, 이 기회를 주저 없이 잡는 것이 맞습니다. 프로젝트의 주도권을 적극적으로 잡아 팀 전체를 원하는 방향으로 이끌어가세요.', en: 'A perfect chance to show leadership arrives today. Aries is the sign that brings out its true ability when standing at the front, so grasping this opportunity without hesitation is right. Actively seize project leadership and guide the whole team in the direction you want.', zh: '今天发挥领导力的绝佳机会到来。白羊座是站在最前面时发挥真正能力的星座，所以毫不犹豫地抓住这个机会是正确的。积极把握项目主导权，引领整个团队走向你想要的方向。', ja: 'リーダーシップを発揮する絶好の機会が今日訪れます。牡羊座は先頭に立つ時こそ真の能力を発揮する星座なので、この機会を迷わず掴むことが正解です。プロジェクトの主導権を積極的に握りチーム全体を望む方向へ導いていってください。', es: 'Llega hoy la oportunidad perfecta para mostrar liderazgo. Aries es el signo que saca su verdadera habilidad cuando está al frente, así que tomar esta oportunidad sin vacilación es lo correcto. Toma activamente el liderazgo del proyecto y guía a todo el equipo en la dirección que deseas.' },
      { ko: '화성의 추진력이 오늘 업무 효율을 극대화합니다. 밀린 과제들을 오늘 한꺼번에 처리할 수 있는 특별한 날로, 이 에너지를 가장 중요한 작업에 집중적으로 쏟으면 놀라운 결과가 나옵니다. 오늘 하루가 끝날 때 목록을 모두 지울 수 있을 것입니다.', en: 'Mars\' drive maximizes work efficiency today. This is a special day to clear all pending tasks at once—pouring this energy focused on the most important work will yield surprising results. You\'ll be able to strike everything off the list by day\'s end.', zh: '火星的推动力今天最大化工作效率。今天是可以一次性处理所有积压任务的特别日子，把这股能量集中倾注在最重要的工作上会有惊人的结果。今天结束时你能划掉清单上的所有项目。', ja: '火星の推進力が今日業務効率を最大化します。溜まった課題を今日一気に処理できる特別な日で、このエネルギーを最も重要な作業に集中的に注げば驚くべき結果が出ます。今日一日が終わる時リストを全て消すことができるでしょう。', es: 'El impulso de Marte maximiza la eficiencia laboral hoy. Este es un día especial para completar todas las tareas pendientes de una vez—verter esta energía enfocada en el trabajo más importante producirá resultados sorprendentes. Podrás tachar todo de la lista al final del día.' },
      { ko: '새로운 사업 아이디어나 기획안이 오늘 상사의 주목을 받습니다. 양자리의 창의적이고 과감한 아이디어는 세상이 아직 보지 못한 방향을 제시하는 능력이기 때문에, 완벽할 때까지 기다리지 말고 과감하게 제안해보세요. 오늘 내놓은 아이디어가 커다란 변화의 시작이 됩니다.', en: 'New business ideas or proposals get your boss\'s attention today. Your Aries creative and bold ideas have the ability to point in directions the world hasn\'t seen yet—don\'t wait for perfection, propose boldly. The idea you put forward today becomes the start of a major change.', zh: '新的商业点子或企划案今天引起上司关注。白羊座创意大胆的想法有指向世界尚未看见方向的能力，不要等到完美，大胆提议吧。今天提出的想法成为重大变化的开始。', ja: '新しいビジネスアイデアや企画が今日上司の注目を受けます。牡羊座の創造的で大胆なアイデアは世界がまだ見ていない方向を示す能力なので完璧になるまで待たずに大胆に提案してみてください。今日出したアイデアが大きな変化の始まりとなります。', es: 'Nuevas ideas de negocio o propuestas captan la atención de tu jefe hoy. Tus ideas creativas y audaces de Aries tienen la capacidad de señalar direcciones que el mundo aún no ha visto—no esperes la perfección, propón con audacia. La idea que presentes hoy se convierte en el inicio de un gran cambio.' },
      { ko: '오늘 시작한 프로젝트는 큰 성공으로 이어질 가능성이 매우 높습니다. 화성의 에너지가 정렬된 지금이 바로 행동의 타이밍이며, 처음 한 발을 내딛는 것이 나머지 아홉 걸음을 이끌어냅니다. 오늘 내딛는 그 첫 발이 미래의 당신에게 가장 중요한 결정이 될 수 있습니다.', en: 'Projects started today have very high probability of great success. Now, with Mars\' energy aligned, is the right timing for action, and taking that first step draws out the remaining nine. That first step you take today may become the most important decision for your future self.', zh: '今天开始的项目很可能取得巨大成功。现在，随着火星能量对齐，正是行动的时机，迈出第一步会引出剩余的九步。今天迈出的那第一步可能成为未来的你最重要的决定。', ja: '今日始めたプロジェクトは大きな成功につながる可能性が非常に高いです。火星のエネルギーが揃った今がまさに行動のタイミングであり最初の一歩を踏み出すことが残りの九歩を引き出します。今日踏み出すその最初の一歩が未来のあなたにとって最も重要な決断になり得ます。', es: 'Los proyectos que inicies hoy tienen muy alta probabilidad de gran éxito. Ahora, con la energía de Marte alineada, es el momento adecuado para actuar, y dar ese primer paso arrastra los nueve restantes. Ese primer paso que das hoy puede convertirse en la decisión más importante para tu yo futuro.' },
      { ko: '경쟁 프레젠테이션이나 면접에서 양자리의 카리스마가 눈부시게 빛을 발합니다. 자신감이 실력 그 자체보다 더 강하게 어필하는 날이므로, 긴장을 에너지로 바꿔 자신감을 무기로 삼으세요. 오늘 당신의 존재감 자체가 최고의 프레젠테이션입니다.', en: 'Your Aries charisma shines brilliantly in competitive presentations or interviews today. Confidence appeals more strongly than skill itself today, so convert nervousness into energy and use confidence as your weapon. Your very presence is the best presentation today.', zh: '今天在竞争性演示或面试中白羊座的魅力耀眼地闪耀。今天自信比实力本身更有力地吸引人，所以把紧张转化为能量，以自信为武器。今天你的存在本身就是最好的演示。', ja: '競争的なプレゼンや面接で牡羊座のカリスマが眩しく光を放ちます。今日は自信が実力そのものより強くアピールする日なので緊張をエネルギーに変えて自信を武器にしてください。今日あなたの存在感自体が最高のプレゼンです。', es: 'Tu carisma ariano brilla brillantemente en presentaciones competitivas o entrevistas hoy. La confianza atrae más fuertemente que la habilidad misma hoy, así que convierte los nervios en energía y usa la confianza como arma. Tu misma presencia es la mejor presentación hoy.' },
      { ko: '동료들을 이끌고 팀 성과를 만들어낼 수 있는 날입니다. 솔선수범하는 모습은 말보다 더 강력한 언어여서, 당신이 먼저 행동으로 보여주면 주변이 자연스럽게 따라옵니다. 오늘 당신의 솔선수범이 팀 전체의 성과로 인정받게 됩니다.', en: 'A day to lead colleagues and create team results. Leading by example is a more powerful language than words—when you show through action first, those around you naturally follow. Your initiative today gets recognized as the entire team\'s achievement.', zh: '可以带领同事创造团队成果的一天。以身作则比言语更有力，当你先用行动展示时，周围的人自然会跟随。今天你的率先垂范被认可为整个团队的成果。', ja: '同僚をリードしてチーム成果を生み出せる日です。率先垂範する姿は言葉より強力な言語であり、あなたが先に行動で示すと周りが自然についてきます。今日あなたの率先垂範がチーム全体の成果として認められます。', es: 'Día para liderar colegas y crear resultados de equipo. Liderar con el ejemplo es un lenguaje más poderoso que las palabras—cuando muestras con acción primero, quienes te rodean naturalmente siguen. Tu iniciativa hoy es reconocida como el logro de todo el equipo.' },
      { ko: '창업이나 사이드 프로젝트를 시작하기에 최적의 운세가 펼쳐집니다. 완벽한 조건을 기다리면 기회는 사라지고, 불완전한 지금 시작하면 우주가 나머지를 채워줍니다. 오늘 첫 번째 행동 하나를 실행에 옮기면 나머지가 뒤따라옵니다.', en: 'Optimal fortune unfolds for starting a business or side project. Waiting for perfect conditions means opportunities vanish; starting imperfectly now means the universe fills in the rest. Execute one first action today and the rest will follow.', zh: '开始创业或副业项目的最佳运势展开。等待完美条件意味着机会消失；现在不完美地开始意味着宇宙会填补其余部分。今天付诸行动第一步，其余会随之而来。', ja: '起業やサイドプロジェクトを始めるのに最適な運勢が開けます。完璧な条件を待てば機会は消え、不完全な今始めれば宇宙が残りを埋めてくれます。今日最初の行動一つを実行に移せば残りがついてきます。', es: 'La fortuna óptima se despliega para comenzar un negocio o proyecto secundario. Esperar condiciones perfectas significa que las oportunidades desaparecen; comenzar imperfectamente ahora significa que el universo llena el resto. Ejecuta una primera acción hoy y el resto seguirá.' },
      { ko: '직장에서 중요한 승진이나 보상의 소식이 올 수 있습니다. 눈에 보이지 않아도 당신의 노력은 항상 기록되어 왔으며, 오늘 그 기록들이 보상으로 되돌아오는 날입니다. 평소의 성실함이 빛을 발하는 이 순간을 당당하게 받아들이세요.', en: 'Promotion or reward news may come from work. Even when invisible, your efforts have always been recorded, and today those records return as rewards. Receive this moment where your usual diligence shines with confidence.', zh: '可能收到职场重要升职或奖励的消息。即使看不见，你的努力一直在被记录，今天那些记录以奖励的形式归来。自信地接受这个平时勤奋闪光的时刻。', ja: '職場で重要な昇進や報酬の知らせが届く可能性があります。見えなくてもあなたの努力はずっと記録されてきており今日その記録が報酬として戻ってくる日です。日頃の誠実さが輝くこの瞬間を堂々と受け取ってください。', es: 'Podrían llegar noticias de ascenso o recompensa del trabajo. Aunque invisible, tu esfuerzo siempre ha sido registrado, y hoy esos registros regresan como recompensas. Recibe con confianza este momento donde tu diligencia habitual brilla.' },
      { ko: '위기 상황에서 당신의 빠른 판단력과 결단력이 조직을 구합니다. 양자리는 압박이 클수록 오히려 더 선명하게 생각하는 능력이 있으며, 오늘 그 능력이 가장 필요한 순간에 완전히 발동됩니다. 주저하지 말고 그 결단을 내려 팀을 이끌어가세요.', en: 'Your quick judgment and decisiveness save the organization in crisis. Aries has the ability to think more clearly the greater the pressure, and today that ability fully activates at the exact moment it\'s most needed. Don\'t hesitate—make that decision and lead the team.', zh: '在危机情况下你快速的判断力和决断力拯救组织。白羊座有压力越大反而思维越清晰的能力，今天那种能力在最需要的时刻完全启动。不要犹豫，做出那个决定，引领团队。', ja: '危機状況であなたの素早い判断力と決断力が組織を救います。牡羊座はプレッシャーが大きいほどむしろより鮮明に考える能力があり今日その能力が最も必要な瞬間に完全に発動されます。躊躇せずその決断を下してチームを導いていってください。', es: 'Tu juicio rápido y decisión salvan a la organización en crisis. Aries tiene la habilidad de pensar más claramente cuanto mayor es la presión, y hoy esa habilidad se activa completamente en el momento exacto en que más se necesita. No dudes—toma esa decisión y lidera al equipo.' },
      { ko: '어려운 협상에서 유리한 결과를 이끌어낼 수 있는 날입니다. 당신의 가치를 스스로 알고 당당하게 요구 사항을 전달할 때, 상대방은 그 확신에 자연스럽게 이끌리게 됩니다. 오늘 협상 테이블에서 양보보다 주장이 더 많은 성과를 가져다줍니다.', en: 'You can achieve favorable outcomes in tough negotiations today. When you know your own value and convey your demands confidently, the other party is naturally drawn to that conviction. At the negotiating table today, assertion brings more results than concession.', zh: '今天可以在困难的谈判中取得有利结果。当你了解自己的价值并自信地传达要求时，对方会自然地被那份确信所吸引。今天在谈判桌上，主张比让步带来更多成果。', ja: '難しい交渉で有利な結果を引き出せる日です。自分の価値を自ら分かって堂々と要求事項を伝える時、相手はその確信に自然と引き寄せられます。今日交渉テーブルでは譲歩より主張がより多くの成果をもたらします。', es: 'Puedes lograr resultados favorables en negociaciones difíciles hoy. Cuando conoces tu propio valor y transmites tus demandas con confianza, la otra parte se siente naturalmente atraída por esa convicción. En la mesa de negociación hoy, la asertividad trae más resultados que la concesión.' },
    ],
    medium: [
      { ko: '새로운 도전보다 현재 업무를 꼼꼼히 마무리하는 데 집중하면 안정적인 성과가 나옵니다. 완성의 힘은 시작의 설렘보다 더 오래 남고, 오늘 하나를 완벽하게 마무리하는 것이 내일의 더 큰 시작을 위한 발판이 됩니다. 목록에서 하나씩 체크하는 만족감을 오늘 충분히 누려보세요.', en: 'Focusing on finishing current work carefully for steady results is today\'s approach. The power of completion lasts longer than the excitement of beginning, and completing one thing perfectly today becomes the foundation for tomorrow\'s greater start. Enjoy the satisfaction of checking things off the list one by one.', zh: '专注于仔细完成当前工作会有稳定的成果。完成的力量比开始的兴奋持续更久，今天完美地完成一件事成为明天更大开始的基础。充分享受今天一项一项打勾的满足感。', ja: '新しい挑戦より現在の業務を丁寧に仕上げることに集中すれば安定的な成果が出ます。完成の力は始まりの設定より長く続き今日一つを完璧に仕上げることが明日のより大きな始まりの足がかりとなります。リストから一つずつチェックする満足感を今日十分に味わってみてください。', es: 'Enfocarte en terminar el trabajo actual cuidadosamente es el enfoque de hoy para resultados estables. El poder de la finalización dura más que la emoción del comienzo, y completar una cosa perfectamente hoy se convierte en el trampolín para el mayor comienzo de mañana. Disfruta la satisfacción de tachar cosas de la lista una por una.' },
      { ko: '업무 속도를 조절하며 체계적으로 진행하면 무리 없이 목표를 달성할 수 있습니다. 양자리는 빠르게 달리는 것이 강점이지만, 오늘은 마라톤 전략이 더 유효합니다. 일정한 페이스로 꾸준히 나아갈 때, 오히려 최단 시간에 가장 멀리 도달하게 됩니다.', en: 'Pace yourself and proceed systematically to achieve goals smoothly. Running fast is Aries\' strength, but marathon strategy is more effective today. Moving forward at a steady consistent pace actually gets you furthest in the shortest time.', zh: '调节工作速度系统性地推进，可以顺利达成目标。快速奔跑是白羊座的优势，但今天马拉松策略更有效。以稳定一致的节奏前进，反而能在最短时间内到达最远的地方。', ja: '業務速度を調節し体系的に進めれば無理なく目標を達成できます。速く走ることが牡羊座の強みですが今日はマラソン戦略の方が有効です。一定のペースでコツコツ進む時むしろ最短時間で最も遠くに到達することになります。', es: 'Regula tu ritmo y procede sistemáticamente para lograr metas sin problemas. Correr rápido es la fortaleza de Aries, pero la estrategia de maratón es más efectiva hoy. Avanzar a un ritmo constante y consistente en realidad te lleva más lejos en el menor tiempo.' },
      { ko: '동료와의 소통에 시간을 투자하면 원활한 협업이 더 좋은 결과를 만들어냅니다. 아이디어가 가장 빛나는 것은 혼자 가다듬을 때가 아니라 다른 관점과 부딪힐 때이기 때문입니다. 오늘 동료 한 명에게 먼저 의견을 묻는 것이 예상치 못한 돌파구가 될 수 있습니다.', en: 'Investing time in communicating with colleagues creates smooth collaboration and better results. Ideas shine most not when refined alone but when colliding with different perspectives. Asking a colleague\'s opinion first today may become an unexpected breakthrough.', zh: '花时间与同事沟通，顺畅的协作创造更好的结果。想法最闪光的不是独自打磨时，而是与不同视角碰撞时。今天先主动问一位同事的意见，可能成为意想不到的突破口。', ja: '同僚とのコミュニケーションに時間を投資すれば円滑な協業がより良い結果を生みます。アイデアが最も輝くのは一人で磨く時ではなく異なる視点とぶつかる時だからです。今日同僚に一人意見を先に聞くことが予想外の突破口になる可能性があります。', es: 'Invertir tiempo comunicándote con colegas crea colaboración fluida y mejores resultados. Las ideas brillan más no cuando se refinan solas sino cuando chocan con diferentes perspectivas. Preguntar la opinión de un colega primero hoy puede convertirse en un avance inesperado.' },
      { ko: '오늘은 주도적 역할보다 서포터 역할에서 의외의 만족감을 느낄 수 있습니다. 지원하는 위치에서 발견되는 시각이 있고, 그 겸손한 자리에서 팀 전체가 어떻게 움직이는지 배울 수 있습니다. 오늘의 서포팅이 내일의 더 나은 리더십을 만들어냅니다.', en: 'You may find unexpected satisfaction in a support role rather than leading today. There are perspectives discovered from a supporting position, and from that humble place you can learn how the whole team moves. Today\'s supporting creates tomorrow\'s better leadership.', zh: '今天在支持角色中可能获得意外的满足感，而非主导角色。从支持位置能发现一些视角，在那个谦逊的地方可以学习整个团队如何运动。今天的支持创造明天更好的领导力。', ja: '今日は主導的な役割よりサポーター役割で意外な満足感を感じることができます。支援する立場から発見される視点があり、その謙虚な場所でチーム全体がどのように動くかを学べます。今日のサポーティングが明日のより良いリーダーシップを生み出します。', es: 'Hoy podrías encontrar satisfacción inesperada en un rol de apoyo en lugar de liderar. Hay perspectivas descubiertas desde una posición de apoyo, y desde ese lugar humilde puedes aprender cómo se mueve todo el equipo. El apoyo de hoy crea el mejor liderazgo de mañana.' },
      { ko: '장기적 커리어 계획을 세우기에 좋은 날입니다. 서두르지 말고 지금 향하고 있는 방향이 진정으로 원하는 목적지인지 점검해보세요. 방향이 맞다면 속도를 높이고, 틀렸다면 지금 수정하는 것이 가장 빠른 길입니다.', en: 'A good day to plan long-term career goals. Don\'t rush—check whether the direction you\'re heading is truly the destination you want. If the direction is right, increase speed; if wrong, correcting now is the fastest path.', zh: '制定长期职业规划的好日子。不要着急，检查一下现在前进的方向是否真的是你想要的目的地。方向正确就加速，不对就现在纠正是最快的路。', ja: '長期的なキャリア計画を立てるのに良い日です。焦らず今向かっている方向が本当に望む目的地かどうか点検してみてください。方向が合っていれば速度を上げ違っていれば今修正することが最も早い道です。', es: 'Un buen día para planificar metas de carrera a largo plazo. No te apresures—verifica si la dirección hacia la que te diriges es verdaderamente el destino que quieres. Si la dirección es correcta, aumenta la velocidad; si es incorrecta, corregir ahora es el camino más rápido.' },
      { ko: '일상 업무에 충실하면서 틈틈이 자기 개발에 시간을 할애하면 미래에 큰 도움이 됩니다. 매일 1%씩 성장하면 일 년 후에는 완전히 다른 사람이 되어 있을 것입니다. 오늘 한 페이지의 독서나 하나의 새로운 기술이 그 시작점이 됩니다.', en: 'Staying diligent at work while investing time in self-development pays off greatly in the future. Growing 1% every day means you\'ll be a completely different person in a year. One page of reading or one new skill today is that starting point.', zh: '忠于日常工作的同时抽空进行自我提升，未来会有很大帮助。每天成长1%，一年后就会成为完全不同的人。今天阅读一页或学一项新技能就是那个起点。', ja: '日常業務に忠実でありながら合間に自己開発に時間を割けば将来大きな助けになります。毎日1%ずつ成長すれば一年後には全く違う人になっているでしょう。今日一ページの読書か一つの新しいスキルがその出発点となります。', es: 'Mantenerse diligente en el trabajo mientras se invierte tiempo en el desarrollo personal paga grandes dividendos en el futuro. Crecer un 1% cada día significa que serás una persona completamente diferente en un año. Una página de lectura o una nueva habilidad hoy es ese punto de partida.' },
      { ko: '중요한 업무 결정은 좀 더 정보를 모은 후 내리는 것이 현명합니다. 양자리의 빠른 본능은 강점이지만, 충분한 데이터 없는 직감은 때로 위험합니다. 조급해하지 말고 하루만 더 기다리면 훨씬 명확한 그림이 보입니다.', en: 'It\'s wise to gather more information before important work decisions. Your Aries quick instinct is a strength, but intuition without sufficient data is sometimes risky. Don\'t rush—wait just one more day and a much clearer picture emerges.', zh: '重要的工作决定最好多收集信息后再做。白羊座快速的本能是优势，但没有足够数据的直觉有时是危险的。不要急躁，再等一天就能看到清晰得多的图景。', ja: '重要な業務決定はもう少し情報を集めてから下すのが賢明です。牡羊座の素早い本能は強みですが十分なデータのない直感は時に危険です。焦らずにもう一日待てばずっと明確な絵が見えてきます。', es: 'Es sabio reunir más información antes de decisiones laborales importantes. Tu instinto rápido de Aries es una fortaleza, pero la intuición sin datos suficientes es a veces arriesgada. No te apresures—espera solo un día más y emerge un cuadro mucho más claro.' },
      { ko: '팀 프로젝트에서 자신의 역할을 정확히 파악하고 범위 내에서 최선을 다하세요. 경계를 벗어나는 것이 때로는 혼란을 만들고, 역할 내에서의 탁월함이 더 큰 신뢰를 얻습니다. 오늘 맡은 부분을 완벽하게 해내는 것이 팀 전체에 기여하는 가장 좋은 방법입니다.', en: 'Identify your role clearly in team projects and do your best within scope. Going beyond boundaries sometimes creates confusion, and excellence within your role earns greater trust. Doing your assigned part perfectly today is the best way to contribute to the whole team.', zh: '准确把握自己在团队项目中的角色，在范围内尽力。越越界有时会造成混乱，在自己角色内的卓越获得更大的信任。今天完美地完成负责的部分是对整个团队贡献最好的方式。', ja: 'チームプロジェクトで自分の役割を正確に把握し範囲内で最善を尽くしてください。境界を超えることが時に混乱を生み役割内での卓越さがより大きな信頼を得ます。今日担当する部分を完璧に成し遂げることがチーム全体に貢献する最善の方法です。', es: 'Identifica tu rol claramente en proyectos de equipo y da lo mejor dentro del alcance. Ir más allá de los límites a veces crea confusión, y la excelencia dentro de tu rol gana mayor confianza. Hacer tu parte asignada perfectamente hoy es la mejor manera de contribuir a todo el equipo.' },
      { ko: '직장 내 인간관계를 다지는 데 에너지를 쓰면 향후 커리어에 큰 자산이 됩니다. 인간관계는 눈에 보이지 않는 자산이지만, 위기의 순간에 가장 먼저 도움이 되는 자원입니다. 오늘 한 사람에게 진심 어린 관심을 표현하면 그 씨앗이 미래에 풍성하게 자라납니다.', en: 'Investing energy in workplace relationships becomes a great career asset. Relationships are invisible assets but are the first resource that helps in moments of crisis. Express genuine interest in one person today and those seeds grow abundantly in the future.', zh: '花精力维护职场人际关系将成为未来职业的重要资产。人际关系是看不见的资产，但在危机时刻是最先能帮助到你的资源。今天向一个人真诚地表达关心，那颗种子将在未来丰盛地成长。', ja: '職場内の人間関係を築くことにエネルギーを使えば今後のキャリアの大きな資産になります。人間関係は目に見えない資産ですが危機の瞬間に最初に役立つリソースです。今日一人に心からの関心を表現すればその種が将来豊かに育ちます。', es: 'Invertir energía en relaciones laborales se convierte en gran activo profesional. Las relaciones son activos invisibles pero son el primer recurso que ayuda en momentos de crisis. Expresar interés genuino en una persona hoy hace que esas semillas crezcan abundantemente en el futuro.' },
      { ko: '작은 성취에도 스스로를 격려하세요. 꾸준한 자기 인정이 장기적 동기부여의 핵심 연료이기 때문입니다. 오늘 하루가 끝날 때 잘 해낸 한 가지를 의식적으로 찾아내어 스스로를 인정해주는 의식을 만들어보세요.', en: 'Encourage yourself even for small achievements. Steady self-recognition is the core fuel of long-term motivation. When today ends, consciously find one thing you did well and create a ritual of recognizing yourself.', zh: '即使是小成就也要鼓励自己。持续的自我认可是长期动力的核心燃料。今天结束时，有意识地找出一件做得好的事，创造认可自己的仪式。', ja: '小さな成果にも自分を励ましてください。着実な自己認定が長期的なモチベーションのコア燃料だからです。今日一日が終わる時うまくできた一つのことを意識的に見つけて自分を認める儀式を作ってみてください。', es: 'Anímato incluso por pequeños logros. El reconocimiento constante de uno mismo es el combustible central de la motivación a largo plazo. Cuando termine el día, encuentra conscientemente una cosa que hiciste bien y crea un ritual de reconocerte a ti mismo/a.' },
    ],
    low: [
      { ko: '상사나 동료와의 의견 충돌이 예상되는 날입니다. 당신의 의견이 옳더라도 전달 방식이 결과를 결정한다는 것을 잊지 마세요. 감정적으로 반응하지 말고 냉정하게 대처하면, 당신의 주장이 훨씬 더 설득력 있게 전달됩니다.', en: 'Clashes with superiors or colleagues are expected today. Even if you\'re right, don\'t forget that the delivery method determines the result. Responding calmly rather than emotionally makes your argument far more persuasive.', zh: '今天预计与上司或同事发生意见冲突。即使你是对的，也不要忘记传达方式决定结果。不要情绪化，冷静应对，你的主张会传达得更有说服力。', ja: '上司や同僚との意見衝突が予想される日です。あなたの意見が正しくても伝え方が結果を決めることを忘れないでください。感情的に反応せず冷静に対処すれば、あなたの主張がずっと説得力を持って伝わります。', es: 'Se esperan choques con superiores o colegas hoy. Incluso si tienes razón, no olvides que la forma de entrega determina el resultado. Responder con calma en lugar de emocionalmente hace que tu argumento sea mucho más persuasivo.' },
      { ko: '성급하게 이직이나 퇴사를 결정하지 마세요. 오늘의 불만이 영구적인 것이 아닐 수 있으며, 충동적 판단이 쌓아온 커리어에 돌이키기 어려운 영향을 줄 수 있습니다. 최소한 일주일의 시간을 주고 같은 감정이 지속된다면 그때 결정하세요.', en: 'Don\'t hastily decide to change jobs or quit. Today\'s dissatisfaction may not be permanent, and impulsive decisions can have hard-to-reverse impacts on the career you\'ve built. Give yourself at least a week, and decide only if the same feeling persists.', zh: '不要仓促决定跳槽或辞职。今天的不满可能不是永久的，冲动的判断可能对积累的职业生涯产生难以挽回的影响。至少给自己一周时间，如果同样的感受持续，那时再决定。', ja: '急いで転職や退社を決めないでください。今日の不満が永続的でない可能性があり衝動的な判断が積み上げてきたキャリアに取り返しのつかない影響を与えます。少なくとも一週間の時間を与えて同じ感情が続くならその時決めてください。', es: 'No decidas precipitadamente cambiar de trabajo o renunciar. La insatisfacción de hoy puede no ser permanente, y las decisiones impulsivas pueden tener impactos difíciles de revertir en la carrera que has construido. Date al menos una semana, y decide solo si el mismo sentimiento persiste.' },
      { ko: '과도한 업무량에 스트레스가 쌓이기 쉬운 날입니다. 모든 것을 혼자 해결하려는 양자리의 본능이 오늘 특히 위험할 수 있으므로, 우선순위를 정해 중요한 것부터 처리하고 나머지는 과감하게 위임하세요. 오늘 살아남는 전략이 장기전에서 이기는 방법입니다.', en: 'Stress builds easily from heavy workload today. Your Aries instinct to solve everything alone can be particularly dangerous today, so prioritize and handle important tasks first, and boldly delegate the rest. The strategy for surviving today is how you win the long game.', zh: '今天过多工作量容易积累压力。白羊座独自解决一切的本能今天尤其危险，所以确定优先级，从重要的事情开始处理，其余大胆委托他人。今天的生存策略就是赢得长期战的方法。', ja: '過度な業務量でストレスが溜まりやすい日です。全てを一人で解決しようとする牡羊座の本能が今日は特に危険な可能性があるので優先順位を決めて重要なものから処理し残りは大胆に委任してください。今日生き残る戦略が長期戦で勝つ方法です。', es: 'El estrés se acumula fácilmente por exceso de trabajo hoy. Tu instinto ariano de resolver todo solo puede ser particularmente peligroso hoy, así que prioriza y maneja las tareas importantes primero, y delega audazmente el resto. La estrategia para sobrevivir hoy es cómo ganas el juego largo.' },
      { ko: '업무 중 실수가 발생할 수 있으니 꼼꼼한 확인과 이중 점검을 생활화하세요. 화성의 에너지가 과열될 때 속도는 빠르지만 정확도가 떨어지는 경향이 있어, 오늘만큼은 느리더라도 정확한 것이 훨씬 더 가치 있습니다. 두 번 확인하는 30초가 수습에 필요한 수 시간을 아껴줍니다.', en: 'Mistakes may occur at work, so make thorough double-checking a habit today. When Mars\' energy overheats, speed is fast but accuracy tends to drop—today, accurate is far more valuable even if slower. The 30 seconds of double-checking saves the hours needed for damage control.', zh: '工作中可能出错，所以今天把仔细的双重检查作为习惯。当火星能量过热时速度快但准确性下降，今天即使慢但准确要有价值得多。双重检查的30秒节省了补救所需的几个小时。', ja: '業務中にミスが発生する可能性があるので丁寧な確認とダブルチェックを今日は習慣化してください。火星のエネルギーが過熱する時速度は速いですが正確さが落ちる傾向があり今日だけは遅くても正確な方がずっと価値があります。二回確認する30秒が対処に必要な数時間を節約してくれます。', es: 'Pueden ocurrir errores en el trabajo, así que haz de la doble verificación cuidadosa un hábito hoy. Cuando la energía de Marte se sobrecalienta, la velocidad es rápida pero la precisión tiende a caer—hoy, ser preciso es mucho más valioso aunque sea más lento. Los 30 segundos de doble verificación ahorran las horas necesarias para el control de daños.' },
      { ko: '자신의 공을 지나치게 주장하다가 팀 분위기를 해칠 수 있는 날입니다. 개인의 공적보다 팀의 성과가 더 크게 빛날 때 결국 모두가 함께 올라가며, 공로를 나누는 여유가 오히려 당신의 리더십을 더 돋보이게 합니다. 오늘의 관대함이 내일의 더 큰 신뢰로 돌아옵니다.', en: 'Claiming your credit too strongly could harm team morale today. When team results shine brighter than individual credit, everyone rises together, and the generosity to share credit actually makes your leadership stand out more. Today\'s generosity returns as greater trust tomorrow.', zh: '今天过度主张自己的功劳可能破坏团队氛围。当团队成果比个人功绩更耀眼时大家共同上升，分享功劳的大度反而让你的领导力更突出。今天的慷慨以明天更大的信任回归。', ja: '自分の功績を主張しすぎるとチームの雰囲気を損なう可能性がある日です。個人の功績よりチームの成果がより大きく輝く時結局みんなが一緒に上がり、功績を分かち合う余裕がむしろあなたのリーダーシップをより際立たせます。今日の寛大さが明日のより大きな信頼として返ってきます。', es: 'Reclamar tu crédito demasiado enérgicamente podría dañar el ambiente del equipo hoy. Cuando los resultados del equipo brillan más que el crédito individual, todos suben juntos, y la generosidad de compartir el crédito en realidad hace que tu liderazgo destaque más. La generosidad de hoy regresa como mayor confianza mañana.' },
      { ko: '새로운 프로젝트에 뛰어들고 싶은 강한 충동이 있지만, 지금은 현재 맡은 일에 집중할 때입니다. 여러 개를 시작하고 하나도 끝내지 못하는 패턴이 반복되면 신뢰가 쌓이기 어렵습니다. 지금 맡은 일을 완벽하게 마무리하는 것이 새로운 기회의 문을 여는 가장 빠른 방법입니다.', en: 'There\'s a strong urge to jump into new projects, but now is the time to focus on current responsibilities. If the pattern of starting many things and completing none repeats, trust is hard to build. Perfectly finishing what you\'re currently handling is the fastest way to open doors to new opportunities.', zh: '有强烈的冲动想投入新项目，但现在应该专注于当前负责的工作。如果开始很多却一件都没完成的模式重复，很难积累信任。完美地完成现在负责的工作，是打开新机会之门最快的方法。', ja: '新しいプロジェクトに飛び込みたい強い衝動がありますが今は現在担当している仕事に集中する時です。たくさん始めて一つも終わらせられないパターンが繰り返されると信頼を積み上げにくくなります。今担当している仕事を完璧に仕上げることが新しい機会の扉を開く最も早い方法です。', es: 'Hay un fuerte impulso de lanzarse a nuevos proyectos, pero ahora es el momento de enfocarse en las responsabilidades actuales. Si el patrón de comenzar muchas cosas y no completar ninguna se repite, es difícil construir confianza. Terminar perfectamente lo que estás manejando actualmente es la forma más rápida de abrir puertas a nuevas oportunidades.' },
      { ko: '직장 내 정치적 상황에 말려들지 않도록 주의해야 합니다. 양자리의 직선적 성격은 복잡한 정치에 피로를 느끼지만, 중립을 유지하는 것이 가장 현명한 전략입니다. 누구의 편도 들지 않고 오로지 일로 자신을 증명하는 것이 오늘의 원칙입니다.', en: 'Beware of getting drawn into office politics today. Your Aries direct nature tires of complex politics, but staying neutral is the wisest strategy. Proving yourself solely through work without taking anyone\'s side is today\'s principle.', zh: '注意不要卷入职场政治。白羊座直线性的性格对复杂的政治感到疲惫，但保持中立是最明智的策略。不站任何人的边，只凭工作证明自己是今天的原则。', ja: '職場内の政治的状況に巻き込まれないよう注意しなければなりません。牡羊座の直線的な性格は複雑な政治に疲れを感じますが中立を保つことが最も賢明な戦略です。誰の味方もせず只仕事で自分を証明することが今日の原則です。', es: 'Ten cuidado de no dejarte arrastrar por la política de oficina hoy. Tu naturaleza directa ariana se cansa de la política compleja, pero mantenerse neutral es la estrategia más sabia. Probarte a ti mismo/a únicamente a través del trabajo sin ponerte del lado de nadie es el principio de hoy.' },
      { ko: '체력 저하가 업무 능력에 영향을 줄 수 있습니다. 오늘은 야근을 피하고 정시 퇴근 후 충분한 회복 시간을 갖는 것이 장기적으로 더 생산적입니다. 컨디션을 잘 관리하는 것이 가장 강력한 성과 향상 전략임을 기억하세요.', en: 'Fatigue may affect work performance today. Avoiding overtime today and taking sufficient recovery time after regular hours is more productive long-term. Remember that managing your condition well is the most powerful performance improvement strategy.', zh: '今天体力下降可能影响工作能力。今天避免加班，正常下班后有充足恢复时间，长期来看更有效率。记住，良好地管理状态是最强大的绩效提升策略。', ja: '体力低下が業務能力に影響を与える可能性があります。今日は残業を避けて定時退社後に十分な回復時間を持つことが長期的にはより生産的です。コンディションをうまく管理することが最も強力なパフォーマンス向上戦略であることを覚えておいてください。', es: 'La fatiga puede afectar el rendimiento laboral hoy. Evitar las horas extra hoy y tomar tiempo de recuperación suficiente después del horario regular es más productivo a largo plazo. Recuerda que gestionar bien tu condición es la estrategia de mejora de rendimiento más poderosa.' },
      { ko: '비판을 개인적 공격으로 받아들이지 마세요. 피드백은 상대방이 당신에게 관심이 있다는 신호이며, 무관심보다 훨씬 가치 있는 것입니다. 건설적 피드백을 성장의 연료로 삼으면 비판받을수록 더 강해지는 양자리의 진정한 모습이 발휘됩니다.', en: 'Don\'t take criticism personally. Feedback is a signal that the other person is interested in you, and far more valuable than indifference. Using constructive feedback as growth fuel reveals the true Aries who grows stronger with every criticism.', zh: '不要把批评当作个人攻击。反馈是对方对你有关注的信号，比无关心有价值得多。把建设性反馈作为成长的燃料，就展现了每受批评就变得更强的白羊座的真实面貌。', ja: '批判を個人的な攻撃として受け取らないでください。フィードバックは相手があなたに関心があるというシグナルであり無関心よりずっと価値があります。建設的なフィードバックを成長の燃料にすれば批判されるほど強くなる牡羊座の真の姿が発揮されます。', es: 'No tomes las críticas como ataques personales. El feedback es una señal de que la otra persona está interesada en ti, y mucho más valioso que la indiferencia. Usar el feedback constructivo como combustible de crecimiento revela al verdadero Aries que se vuelve más fuerte con cada crítica.' },
      { ko: '독단적으로 일을 진행하면 주변의 반발을 살 수 있습니다. 혼자서 빠르게 가는 것보다 함께 천천히 가는 것이 더 멀리 가는 방법이기 때문에, 의사결정 전 팀과 상의하는 습관이 장기적으로 더 큰 성과를 만들어냅니다. 오늘 팀원들의 의견을 먼저 구해보세요.', en: 'Working unilaterally may cause pushback. Going slowly together reaches further than going quickly alone, so the habit of consulting the team before decisions creates greater results long-term. Seek your team members\' opinions first today.', zh: '独断专行可能引起周围的反感。一起慢慢走比独自快走走得更远，所以在做决定前征询团队意见的习惯，长期来看能创造更大的成果。今天先征求团队成员的意见。', ja: '独断的に仕事を進めると周りの反発を買う可能性があります。一人で速く行くより一緒にゆっくり行く方がより遠くへ行けるので意思決定前にチームと相談する習慣が長期的にはより大きな成果を生み出します。今日チームメンバーの意見を先に求めてみてください。', es: 'Trabajar unilateralmente puede causar resistencia. Ir lentamente juntos llega más lejos que ir rápidamente solo, así que el hábito de consultar al equipo antes de las decisiones crea mayores resultados a largo plazo. Busca las opiniones de tus compañeros de equipo primero hoy.' },
    ],
  },
  health: {
    high: [
      { ko: '화성의 활력이 오늘 완전한 최고조에 달했습니다. 몸이 이렇게 준비된 날에 새로운 운동을 시작하거나 기존 운동의 강도를 높이면 최상의 결과가 나옵니다. 오늘 땀 흘리며 도전하면 그 성취감이 내일의 습관이 됩니다.', en: 'Mars\' vitality reaches its complete peak today. Starting new exercises or increasing existing exercise intensity on a day your body is this prepared yields the best results. Challenge yourself with sweat today and that achievement becomes tomorrow\'s habit.', zh: '火星的活力今天达到完全的最高点。在身体这样准备好的日子开始新运动或提高现有运动强度会得到最好的结果。今天挥汗挑战，那份成就感会成为明天的习惯。', ja: '火星の活力が今日完全な最高潮に達しました。体がこれほど準備できた日に新しい運動を始めたり既存の運動強度を高めれば最高の結果が出ます。今日汗を流して挑戦すればその達成感が明日の習慣となります。', es: 'La vitalidad de Marte alcanza su pico completo hoy. Comenzar nuevos ejercicios o aumentar la intensidad del ejercicio existente en un día en que tu cuerpo está tan preparado produce los mejores resultados. Desafíate con sudor hoy y ese logro se convierte en el hábito de mañana.' },
      { ko: '몸과 마음의 에너지가 넘쳐나는 날입니다. 그동안 미뤄둔 건강 관련 목표에 오늘 드디어 도전할 때가 왔습니다. 에너지가 이렇게 충만할 때 시작한 습관은 지속될 가능성이 훨씬 높으므로, 오늘의 첫 행동이 평생 가는 건강 루틴의 씨앗이 됩니다.', en: 'Physical and mental energy is overflowing today. The time has finally come to challenge those health goals you\'ve been postponing. Habits started when energy is this full are far more likely to continue, so today\'s first action becomes the seed of a lifelong health routine.', zh: '身心能量满溢的一天。今天终于到了挑战那些一直推迟的健康目标的时候了。在能量如此充沛时开始的习惯持续的可能性大得多，所以今天的第一个行动成为终身健康习惯的种子。', ja: '体と心のエネルギーが溢れる日です。これまで先延ばしにしていた健康目標に今日ついに挑戦する時が来ました。エネルギーがこれほど充実している時に始めた習慣は継続する可能性がずっと高いので今日の最初の行動が生涯続く健康ルーティンの種となります。', es: 'La energía física y mental desborda hoy. Ha llegado finalmente el momento de desafiar esas metas de salud que has estado posponiendo. Los hábitos iniciados cuando la energía es tan plena tienen mucha más probabilidad de continuar, así que la primera acción de hoy se convierte en la semilla de una rutina de salud de por vida.' },
      { ko: '회복력이 뛰어난 시기입니다. 몸의 작은 불편함도 빠르게 나아질 수 있으며, 이 회복력을 활용해 조금 더 적극적인 건강 관리에 나서기 좋은 날입니다. 오늘 몸이 보내는 좋은 신호에 감사하고 그 에너지를 현명하게 활용하세요.', en: 'Recovery power is excellent now. Even small physical discomforts can heal quickly, and today is a good day to leverage this recovery power for more proactive health management. Be grateful for the good signals your body sends today and use that energy wisely.', zh: '恢复力出色的时期。身体的小不适也能很快好转，今天是利用这种恢复力进行更积极健康管理的好日子。感谢今天身体发出的好信号，明智地利用那份能量。', ja: '回復力が優れた時期です。体の小さな不快感も早く良くなる可能性があり、この回復力を活用してより積極的な健康管理に取り組むのに良い日です。今日体が送る良いサインに感謝してそのエネルギーを賢く活用してください。', es: 'El poder de recuperación es excelente ahora. Incluso las pequeñas molestias físicas pueden sanar rápidamente, y hoy es un buen día para aprovechar este poder de recuperación para una gestión de salud más proactiva. Agradece las buenas señales que tu cuerpo envía hoy y usa esa energía sabiamente.' },
      { ko: '신체적 도전이 오히려 에너지를 더 강하게 끌어올리는 날입니다. 고강도 운동에 도전해보면 시작하기 전보다 훨씬 더 활력이 넘치는 자신을 발견하게 됩니다. 양자리의 몸은 도전받을 때 가장 강해지도록 설계되어 있으니 오늘 그 본능을 따르세요.', en: 'Physical challenges actually boost your energy even stronger today. Trying high-intensity workouts will let you discover yourself far more energetic than before starting. The Aries body is designed to be strongest when challenged, so follow that instinct today.', zh: '今天身体挑战反而能更强烈地提升能量。尝试高强度运动，会发现比开始前活力充沛得多的自己。白羊座的身体被设计成受挑战时最强，所以今天遵循那种本能。', ja: '身体的なチャレンジがむしろエネルギーをより強く引き上げる日です。高強度の運動に挑戦してみれば始める前よりずっと活力溢れる自分を発見することになります。牡羊座の体は挑戦を受ける時に最も強くなるように設計されているので今日その本能に従ってください。', es: 'Los desafíos físicos potencian tu energía aún más fuertemente hoy. Probar entrenamientos de alta intensidad te permitirá descubrirte mucho más enérgico/a que antes de empezar. El cuerpo de Aries está diseñado para ser más fuerte cuando se le desafía, así que sigue ese instinto hoy.' },
      { ko: '면역력이 강화되는 시기입니다. 규칙적인 운동과 균형 잡힌 영양 섭취로 건강을 더욱 다지면, 지금 쌓는 면역력이 미래의 건강 자산이 됩니다. 오늘 시작하는 건강 루틴이 당신의 몸에 오래 기억됩니다.', en: 'Immunity strengthens now. Solidifying health further with regular exercise and balanced nutrition makes the immunity you build now a future health asset. The health routine you start today is long remembered by your body.', zh: '免疫力增强的时期。通过规律运动和均衡营养摄入进一步巩固健康，现在积累的免疫力成为未来的健康资产。今天开始的健康习惯会被你的身体长久铭记。', ja: '免疫力が強化される時期です。規則的な運動とバランスの取れた栄養摂取で健康をさらに固めれば今築いている免疫力が未来の健康資産となります。今日始める健康ルーティンがあなたの体に長く記憶されます。', es: 'La inmunidad se fortalece ahora. Consolidar aún más la salud con ejercicio regular y nutrición equilibrada convierte la inmunidad que construyes ahora en un activo de salud futuro. La rutina de salud que comiences hoy es recordada por tu cuerpo por mucho tiempo.' },
      { ko: '야외 활동에 최적인 컨디션입니다. 등산이나 러닝으로 자연 속에서 에너지를 충전하면, 화성의 불꽃이 대지의 에너지와 만나 시너지를 만들어냅니다. 오늘 밖으로 나가는 선택 하나가 몸과 마음 모두를 리셋시켜줄 것입니다.', en: 'Perfect condition for outdoor activities. Recharging energy in nature through hiking or running makes Mars\' flame meet earth\'s energy and create synergy. The one choice to go outside today will reset both body and mind.', zh: '户外活动的最佳状态。通过登山或跑步在大自然中充电，火星的火焰与大地能量相遇创造协同效应。今天外出的一个选择将重置身心两者。', ja: '野外活動に最適なコンディションです。登山やランニングで自然の中でエネルギーを充電すれば火星の炎が大地のエネルギーと出会ってシナジーを生み出します。今日外に出るという一つの選択が体と心両方をリセットしてくれるでしょう。', es: 'Condición perfecta para actividades al aire libre. Recargar energía en la naturaleza a través del senderismo o el running hace que la llama de Marte se encuentre con la energía de la tierra y cree sinergia. La única elección de salir hoy reiniciará tanto el cuerpo como la mente.' },
      { ko: '오늘의 운동은 평소보다 훨씬 더 좋은 결과를 가져옵니다. 개인 기록 갱신에 도전할 수 있는 최적의 날이어서, 목표를 조금 더 높게 설정해보세요. 한계를 1%만 더 밀어붙이는 것이 오늘 당신의 몸이 기억하는 가장 강한 순간이 됩니다.', en: 'Today\'s workout brings results far better than usual. This is the optimal day to challenge your personal records, so set your target a bit higher. Pushing the limit just 1% more becomes the strongest moment your body remembers today.', zh: '今天的运动比平时带来好得多的结果。这是挑战个人记录的最佳日子，所以把目标设得稍高一点。把极限再推进1%成为今天你的身体记住的最强瞬间。', ja: '今日の運動はいつもよりずっと良い結果をもたらします。自己記録更新に挑戦できる最適な日なので目標を少し高く設定してみてください。限界をあと1%だけ押し進めることが今日あなたの体が記憶する最も強い瞬間となります。', es: 'El ejercicio de hoy trae resultados mucho mejores que de costumbre. Este es el día óptimo para desafiar tus récords personales, así que establece tu objetivo un poco más alto. Empujar el límite solo un 1% más se convierte en el momento más fuerte que tu cuerpo recuerda hoy.' },
      { ko: '숙면을 취하기 좋은 최적의 컨디션입니다. 오늘 밤 전자기기를 일찍 내려놓고 푹 쉬면, 내일 아침 지금보다 훨씬 더 활력 넘치는 상태로 하루를 시작할 수 있습니다. 좋은 수면이 당신의 가장 강력한 건강 투자임을 오늘 몸소 경험하세요.', en: 'Optimal condition for deep sleep tonight. Putting down electronics early tonight and resting well lets you start tomorrow morning in a state far more vibrant than now. Experience firsthand today that good sleep is your most powerful health investment.', zh: '今晚深度睡眠的最佳状态。今晚早点放下电子设备好好休息，明天早上就能以比现在活力充沛得多的状态开始一天。今天亲身体验良好的睡眠是你最强大的健康投资。', ja: '熟睡を取るのに最適なコンディションです。今夜電子機器を早めに置いてぐっすり休めば明日の朝今よりずっと活力溢れる状態で一日を始めることができます。良い睡眠があなたの最も強力な健康投資であることを今日自ら体験してください。', es: 'Condición óptima para dormir profundamente esta noche. Dejar los dispositivos electrónicos temprano esta noche y descansar bien te permite comenzar mañana por la mañana en un estado mucho más vibrante que ahora. Experimenta de primera mano hoy que el buen sueño es tu inversión de salud más poderosa.' },
      { ko: '건강한 식습관을 시작하기에 완벽한 타이밍입니다. 식단 개선은 오늘처럼 에너지가 충만하고 동기가 높을 때 시작해야 지속됩니다. 완벽한 변화를 목표로 하지 말고 오늘 한 가지만 개선해도 그것이 출발점이 됩니다.', en: 'Perfect timing to start healthy eating habits. Dietary improvement needs to start when energy and motivation are high like today to be sustained. Don\'t aim for perfect change—improving just one thing today is the starting point.', zh: '开始健康饮食习惯的完美时机。饮食改善需要在今天这样能量充沛、动力高涨时开始才能持续。不要目标完美的改变，今天只改善一件事也是起点。', ja: '健康的な食習慣を始めるのに完璧なタイミングです。食事改善は今日のようにエネルギーが充実してモチベーションが高い時に始めてこそ継続されます。完璧な変化を目標にせず今日一つだけ改善してもそれが出発点となります。', es: 'Momento perfecto para comenzar hábitos alimenticios saludables. La mejora dietética necesita comenzar cuando la energía y motivación son altas como hoy para ser sostenida. No apuntes al cambio perfecto—mejorar solo una cosa hoy es el punto de partida.' },
      { ko: '스트레스 해소가 잘 되는 특별한 날입니다. 운동이나 명상으로 심신의 균형을 완성하면, 지금 당신 안에 쌓인 긴장들이 자연스럽게 풀리는 것을 경험할 수 있습니다. 오늘 20분의 자기 돌봄이 이번 주 전체의 건강을 결정합니다.', en: 'A special day when stress relief comes easily. Completing the mind-body balance through exercise or meditation lets you experience the tension accumulated within you naturally releasing. 20 minutes of self-care today determines your entire week\'s health.', zh: '压力容易释放的特别一天。通过运动或冥想完善身心平衡，可以体验到积累在你内心的紧张自然消解。今天20分钟的自我关怀决定这整个星期的健康。', ja: 'ストレス解消がうまくいく特別な日です。運動や瞑想で心身のバランスを完成させると今あなたの中に溜まった緊張が自然にほぐれていくのを体験できます。今日20分の自己ケアがこの週全体の健康を決めます。', es: 'Un día especial cuando el alivio del estrés llega fácilmente. Completar el equilibrio mente-cuerpo a través del ejercicio o la meditación te permite experimentar la tensión acumulada dentro de ti liberándose naturalmente. 20 minutos de autocuidado hoy determina la salud de toda tu semana.' },
    ],
    medium: [
      { ko: '전반적으로 안정적인 건강 상태이지만 두통에 주의해야 합니다. 수분 부족이 양자리가 자주 겪는 두통의 주요 원인이므로, 오늘은 의식적으로 물을 더 자주 마셔보세요. 작은 습관 하나가 오늘 하루의 컨디션을 크게 좌우합니다.', en: 'Overall stable health, but watch for headaches. Insufficient hydration is a major cause of the headaches Aries often experiences, so consciously drink water more frequently today. One small habit greatly affects your condition for the whole day.', zh: '整体健康状态稳定，但要注意头痛。水分不足是白羊座常常经历头痛的主要原因，所以今天有意识地更频繁地喝水。一个小习惯大大影响今天一整天的状态。', ja: '全般的に安定した健康状態ですが頭痛に注意してください。水分不足が牡羊座がよく経験する頭痛の主な原因なので今日は意識的に水を頻繁に飲んでみてください。小さな習慣一つが今日一日のコンディションを大きく左右します。', es: 'Salud estable en general, pero ten cuidado con los dolores de cabeza. La hidratación insuficiente es la principal causa de los dolores de cabeza que Aries frecuentemente experimenta, así que bebe agua con más frecuencia conscientemente hoy. Un pequeño hábito afecta enormemente tu condición durante todo el día.' },
      { ko: '무리하지 않는 선에서 가벼운 산책이나 스트레칭으로 몸을 풀어주는 것이 좋습니다. 쉬는 날에도 몸을 완전히 정지시키기보다 가벼운 움직임이 혈액 순환을 도와 더 빠른 회복을 이끌어냅니다. 오늘의 15분 스트레칭이 내일의 더 강한 운동을 준비합니다.', en: 'Light walks or stretching without overexertion to loosen the body is recommended. Even on rest days, light movement rather than complete stillness helps circulation and leads to faster recovery. 15 minutes of stretching today prepares tomorrow\'s stronger workout.', zh: '在不勉强的范围内做轻松的散步或伸展运动舒展身体很好。即使在休息日，轻微的运动而非完全静止有助于血液循环，带来更快的恢复。今天15分钟的拉伸为明天更强的运动做准备。', ja: '無理しない範囲で軽い散歩やストレッチで体をほぐすのが良いです。休みの日でも体を完全に止めるより軽い動きが血液循環を助けてより早い回復をもたらします。今日の15分のストレッチが明日のより強い運動を準備します。', es: 'Se recomienda caminatas ligeras o estiramientos sin exceso para aflojar el cuerpo. Incluso en días de descanso, el movimiento ligero en lugar de la quietud completa ayuda a la circulación y lleva a una recuperación más rápida. 15 minutos de estiramiento hoy prepara el entrenamiento más fuerte de mañana.' },
      { ko: '에너지 레벨이 보통 수준이므로 과격한 운동보다 유산소 위주의 활동이 오늘 더 적합합니다. 몸이 허용하는 범위에서 최선을 다하는 것이 부상 없이 지속 가능한 건강을 만드는 법입니다. 오늘의 적절한 운동이 내일의 더 강한 몸을 만드는 토대가 됩니다.', en: 'Energy at normal levels, so cardio-focused activities suit better than intense workouts today. Doing your best within what your body allows is how you create sustainable health without injury. Today\'s appropriate exercise is the foundation that builds tomorrow\'s stronger body.', zh: '能量水平一般，今天有氧为主的活动比剧烈运动更合适。在身体允许的范围内尽力是无伤创建可持续健康的方法。今天适当的运动是构建明天更强壮身体的基础。', ja: 'エネルギーレベルが普通なので激しい運動より有酸素中心の活動が今日より適しています。体が許す範囲で最善を尽くすことが怪我なく持続可能な健康を作る方法です。今日の適切な運動が明日のより強い体を作る土台となります。', es: 'La energía en nivel normal, así que las actividades enfocadas en cardio son más adecuadas que los entrenamientos intensos hoy. Dar lo mejor dentro de lo que tu cuerpo permite es cómo se crea una salud sostenible sin lesiones. El ejercicio apropiado de hoy es la base que construye el cuerpo más fuerte de mañana.' },
      { ko: '식사 시간을 규칙적으로 맞추면 하루 컨디션이 한결 좋아집니다. 양자리는 바쁜 일에 열중하다 끼니를 거르는 경향이 있는데, 이것이 에너지 저하와 집중력 감소로 이어지는 주요 원인입니다. 오늘만큼은 세 끼를 제때 챙겨 몸에 안정된 신호를 보내세요.', en: 'Regular meal times significantly improve your daily condition. Aries tends to skip meals while absorbed in busy work, and this is a major cause of energy drops and concentration loss. At least today, eat all three meals on time and send stable signals to your body.', zh: '规律进餐时间会大幅改善一天的状态。白羊座有专注忙碌工作时跳过用餐的倾向，这是能量下降和专注力减退的主要原因。至少今天，按时吃三餐，向身体发送稳定的信号。', ja: '食事時間を規則的にすれば一日のコンディションがぐっと良くなります。牡羊座は忙しい仕事に熱中して食事を抜く傾向がありますが、これがエネルギー低下と集中力の減退につながる主な原因です。今日だけでも三食を時間通りに食べて体に安定したシグナルを送ってください。', es: 'Los horarios regulares de comida mejoran significativamente tu condición diaria. Aries tiende a saltarse comidas mientras está absorbido en trabajo ocupado, y esto es una causa principal de caídas de energía y pérdida de concentración. Al menos hoy, come las tres comidas a tiempo y envía señales estables a tu cuerpo.' },
      { ko: '충분한 수면이 내일의 활력을 결정합니다. 화성의 에너지가 들끓는 날일수록 오히려 더 깊은 수면이 필요하며, 오늘 일찍 잠자리에 드는 선택이 내일 두 배의 에너지로 돌아옵니다. 수면을 게으름이 아닌 전략적 회복으로 인식하세요.', en: 'Sufficient sleep determines tomorrow\'s vitality. The more Mars\' energy boils, the deeper sleep is needed, and going to bed early today returns as double energy tomorrow. Recognize sleep not as laziness but as strategic recovery.', zh: '充足的睡眠决定明天的活力。火星能量越沸腾的日子，反而需要更深的睡眠，今天早睡的选择以明天双倍的能量归来。把睡眠认识为战略性恢复而非懒惰。', ja: '十分な睡眠が明日の活力を決めます。火星のエネルギーが沸き立つ日ほどむしろより深い睡眠が必要であり今日早めに就寝するという選択が明日倍のエネルギーとして返ってきます。睡眠を怠惰ではなく戦略的な回復として認識してください。', es: 'El sueño suficiente determina la vitalidad de mañana. Cuanto más hierve la energía de Marte, más profundo es el sueño necesario, y acostarse temprano hoy regresa como el doble de energía mañana. Reconoce el sueño no como pereza sino como recuperación estratégica.' },
      { ko: '양자리가 취약한 머리와 목 부위의 긴장을 풀어주는 마사지가 오늘 특히 도움이 됩니다. 두통이나 목 결림을 느낀다면 그것은 몸이 보내는 과부하 신호이므로, 지금 바로 5분 마사지로 응답해주세요. 작은 자기 돌봄이 더 큰 문제를 예방합니다.', en: 'Massage to release tension in Aries\' vulnerable head and neck areas is especially helpful today. If you feel headaches or neck stiffness, that\'s your body\'s overload signal—respond right now with a 5-minute massage. Small self-care prevents bigger problems.', zh: '今天缓解白羊座脆弱的头部和颈部紧张的按摩特别有帮助。如果感到头痛或颈部僵硬，那是身体发出的过载信号，立刻用5分钟按摩来回应。小小的自我关怀预防更大的问题。', ja: '牡羊座が弱い頭と首の部位の緊張をほぐすマッサージが今日は特に役立ちます。頭痛や首のこりを感じたらそれは体が送る過負荷サインなので今すぐ5分マッサージで応えてください。小さなセルフケアがより大きな問題を防ぎます。', es: 'El masaje para liberar tensión en las vulnerables áreas de cabeza y cuello de Aries es especialmente útil hoy. Si sientes dolores de cabeza o rigidez en el cuello, esa es la señal de sobrecarga de tu cuerpo—responde ahora mismo con un masaje de 5 minutos. El pequeño autocuidado previene problemas mayores.' },
      { ko: '적당한 운동은 유지하되 과도한 경쟁 운동은 피하세요. 부상의 위험이 평소보다 높은 날이어서, 자신의 한계보다 조금 낮은 수준에서 운동하는 것이 현명합니다. 오늘의 여유가 내일 더 강하게 훈련할 수 있는 토대를 만들어줍니다.', en: 'Maintain moderate exercise but avoid excessive competitive sports. Injury risk is higher than usual today, so exercising slightly below your limit is wise. Today\'s margin creates the foundation for training even stronger tomorrow.', zh: '保持适度运动但避免过度竞技运动。今天受伤风险比平时高，所以在略低于自身极限的水平运动更明智。今天的余裕为明天更强的训练打下基础。', ja: '適度な運動は維持しつつ過度な競争的運動は避けてください。今日は怪我のリスクが普段より高いので自分の限界より少し低いレベルで運動するのが賢明です。今日の余裕が明日より強くトレーニングできる土台を作ってくれます。', es: 'Mantén ejercicio moderado pero evita deportes competitivos excesivos. El riesgo de lesión es más alto que de costumbre hoy, así que ejercitarse ligeramente por debajo de tu límite es sabio. El margen de hoy crea la base para entrenar más fuerte mañana.' },
      { ko: '업무 중 눈의 피로가 쌓일 수 있으니 주기적으로 눈 운동과 먼 곳 바라보기를 실행하세요. 20분 집중 후 20초간 20피트 멀리 바라보는 20-20-20 규칙을 오늘 한번 적용해보세요. 눈 건강이 전체 컨디션에 미치는 영향은 생각보다 훨씬 큽니다.', en: 'Eye fatigue may build during work, so do eye exercises and look at distant objects regularly. Try applying the 20-20-20 rule today: after 20 minutes of focus, look 20 feet away for 20 seconds. Eye health has a far greater impact on your overall condition than you might think.', zh: '工作中眼睛疲劳可能累积，所以定期做眼部运动和远眺。今天试着应用20-20-20规则：专注20分钟后，向20英尺外看20秒。眼睛健康对整体状态的影响比你想象的大得多。', ja: '業務中に目の疲れが溜まる可能性があるので定期的に目の運動と遠くを見ることを実行してください。20分集中した後20秒間20フィート先を見る20-20-20ルールを今日一度適用してみてください。目の健康が全体のコンディションに与える影響は思ったよりずっと大きいです。', es: 'La fatiga ocular puede acumularse durante el trabajo, así que haz ejercicios oculares y mira objetos distantes regularmente. Intenta aplicar la regla 20-20-20 hoy: después de 20 minutos de enfoque, mira a 20 pies de distancia por 20 segundos. La salud ocular tiene un impacto mucho mayor en tu condición general de lo que podrías pensar.' },
      { ko: '건강 루틴을 점검하고 개선할 부분을 찾아보는 좋은 날입니다. 작은 습관 변화가 큰 차이를 만든다는 것은 사실이며, 오늘 발견한 개선점 하나를 내일부터 실행하겠다고 구체적으로 정해보세요. 계획이 구체적일수록 실행될 가능성이 높아집니다.', en: 'A good day to review your health routine and find areas to improve. It\'s true that small habit changes make big differences, so specifically decide to implement one improvement you discover today starting tomorrow. The more concrete a plan, the more likely it is to be executed.', zh: '检查健康习惯并找出改进之处的好日子。小习惯的改变确实会带来大变化，今天发现一个改进点，具体决定从明天开始实行。计划越具体，执行的可能性越高。', ja: '健康ルーティンを点検し改善できる部分を探すのに良い日です。小さな習慣の変化が大きな違いを生むことは事実であり今日発見した改善点を明日から実行すると具体的に決めてみてください。計画が具体的なほど実行される可能性が高まります。', es: 'Un buen día para revisar tu rutina de salud y encontrar áreas de mejora. Es cierto que los pequeños cambios de hábitos hacen grandes diferencias, así que decide específicamente implementar una mejora que descubras hoy comenzando mañana. Cuanto más concreto sea el plan, más probable es que se ejecute.' },
      { ko: '과도한 카페인 섭취를 줄이고 허브차로 대체하면 심신 안정에 도움이 됩니다. 화성의 에너지가 이미 충분히 높으므로 카페인은 오히려 과부하를 일으킬 수 있으며, 차 한 잔의 여유가 하루 전체의 균형을 잡아줍니다. 오늘 오후는 허브차를 마시며 잠깐 숨을 고르세요.', en: 'Reducing excessive caffeine and switching to herbal tea helps mental and physical stability. Since Mars\' energy is already high enough, caffeine can cause overload, and the leisure of one cup of tea balances the whole day. Take a moment to breathe with herbal tea this afternoon.', zh: '减少过多咖啡因摄入，换成草本茶有助于身心安定。由于火星能量已经足够高，咖啡因反而可能造成过载，一杯茶的从容平衡整天的节奏。今天下午喝着草本茶稍作喘息。', ja: '過度なカフェイン摂取を減らしてハーブティーに替えると心身の安定に役立ちます。火星のエネルギーがすでに十分に高いのでカフェインはむしろ過負荷を引き起こす可能性があり、お茶一杯の余裕が一日全体のバランスを整えてくれます。今日の午後はハーブティーを飲みながら少し一息ついてください。', es: 'Reducir la cafeína excesiva y cambiarla por té herbal ayuda a la estabilidad mental y física. Como la energía de Marte ya es suficientemente alta, la cafeína puede causar sobrecarga, y la tranquilidad de una taza de té equilibra todo el día. Tómate un momento para respirar con té herbal esta tarde.' },
    ],
    low: [
      { ko: '두통이나 편두통 증상이 나타날 수 있는 날입니다. 화성의 과열된 에너지와 정신적 긴장이 결합되면 머리에 압박감이 오는 경향이 있으므로, 스트레스를 줄이고 충분한 휴식을 취하는 것이 최우선입니다. 아프기 전에 예방하는 것이 가장 강한 건강 전략입니다.', en: 'Headaches or migraines may appear today. When Mars\' overheated energy combines with mental tension, there\'s a tendency for pressure in the head, so reducing stress and getting sufficient rest is the top priority. Preventing before getting sick is the strongest health strategy.', zh: '今天可能出现头痛或偏头痛症状。当火星过热能量与精神紧张结合时，头部容易感到压力，所以减少压力和充分休息是最优先的。在生病前预防是最强大的健康策略。', ja: '頭痛や偏頭痛の症状が現れる可能性がある日です。火星の過熱したエネルギーと精神的な緊張が結びつくと頭に圧迫感が来る傾向があるのでストレスを減らし十分な休息を取ることが最優先です。病気になる前に予防することが最も強い健康戦略です。', es: 'Pueden aparecer dolores de cabeza o migrañas hoy. Cuando la energía sobrecalentada de Marte se combina con la tensión mental, hay una tendencia a la presión en la cabeza, así que reducir el estrés y descansar suficientemente es la máxima prioridad. Prevenir antes de enfermarse es la estrategia de salud más fuerte.' },
      { ko: '과격한 운동 중 부상에 주의해야 하는 날입니다. 준비 운동을 충분히 하고 무리한 동작을 피하면, 오늘의 조심성이 내일도 운동을 계속할 수 있게 해줍니다. 부상은 한 번의 실수로 수주간의 훈련을 날려버리므로 오늘만큼은 안전 제일입니다.', en: 'Watch for injuries during intense exercise today. Warming up thoroughly and avoiding risky moves means today\'s caution lets you continue exercising tomorrow too. An injury from one mistake can erase weeks of training, so safety first today.', zh: '今天剧烈运动中要注意受伤。充分热身并避免勉强的动作，今天的谨慎让你明天也能继续运动。一次失误的受伤可以让数周的训练付诸东流，所以今天安全第一。', ja: '激しい運動中の怪我に注意しなければならない日です。準備運動を十分にし無理な動作を避ければ今日の注意深さが明日も運動を続けられるようにしてくれます。怪我は一度のミスで数週間のトレーニングを台無しにするので今日だけは安全第一です。', es: 'Ten cuidado con las lesiones durante el ejercicio intenso hoy. Calentar bien y evitar movimientos riesgosos significa que la precaución de hoy te permite continuar ejercitándote mañana también. Una lesión por un error puede borrar semanas de entrenamiento, así que seguridad ante todo hoy.' },
      { ko: '화성의 과열된 에너지로 불면증이 올 수 있습니다. 자기 직전까지 화면을 보면 뇌가 각성 상태를 유지해 잠들기 어려워지므로, 취침 1시간 전부터 전자기기 사용을 줄이세요. 오늘 밤의 숙면이 내일의 화성 에너지를 두 배로 만들어줍니다.', en: 'Mars\' overheated energy may cause insomnia. Looking at screens right until bedtime keeps the brain in an alert state making it hard to fall asleep, so reduce device use from 1 hour before sleep. Tonight\'s deep sleep doubles tomorrow\'s Mars energy.', zh: '火星过热的能量可能导致失眠。睡前一直盯着屏幕会使大脑保持觉醒状态，难以入睡，所以睡前1小时减少电子设备使用。今晚的深度睡眠让明天的火星能量加倍。', ja: '火星の過熱したエネルギーで不眠症になる可能性があります。直前まで画面を見ると脳が覚醒状態を保って眠りにくくなるので就寝1時間前から電子機器の使用を減らしてください。今夜の熟睡が明日の火星エネルギーを倍にしてくれます。', es: 'La energía sobrecalentada de Marte puede causar insomnio. Mirar pantallas justo hasta la hora de dormir mantiene el cerebro en estado de alerta dificultando conciliar el sueño, así que reduce el uso de dispositivos desde 1 hora antes de dormir. El sueño profundo de esta noche duplica la energía de Marte de mañana.' },
      { ko: '분노나 스트레스가 신체 증상으로 나타날 수 있는 날입니다. 감정 관리가 곧 건강 관리라는 사실을 오늘만큼은 몸소 체험하게 됩니다. 긴장이 느껴질 때 깊게 숨을 들이쉬는 간단한 행동 하나가 몸 전체에 신호를 보내 차분하게 만들어줍니다.', en: 'Anger or stress may manifest as physical symptoms today. You\'ll experience firsthand today that emotional management is health management. One simple act of breathing deeply when tension is felt sends a signal to the whole body and calms it.', zh: '今天愤怒或压力可能以身体症状表现。今天会亲身体验到情绪管理就是健康管理这一事实。感到紧张时深深吸气这一简单行为向全身发送信号，使其平静下来。', ja: '怒りやストレスが身体症状として現れる可能性がある日です。感情管理がすなわち健康管理だという事実を今日だけは自ら体験することになります。緊張を感じた時に深く息を吸うという簡単な行動一つが全身にシグナルを送って落ち着かせてくれます。', es: 'La ira o el estrés pueden manifestarse como síntomas físicos hoy. Experimentarás de primera mano hoy que la gestión emocional es gestión de salud. Un simple acto de respirar profundamente cuando se siente tensión envía una señal a todo el cuerpo y lo calma.' },
      { ko: '과식이나 자극적인 음식 섭취를 조심해야 하는 날입니다. 양자리의 충동적 본능이 식사에도 나타나 폭식이나 자극적 음식을 선택하기 쉬운 날이어서, 소화기에 부담을 주지 않도록 천천히 먹고 절제하는 것이 중요합니다. 오늘의 식사 선택이 내일의 몸 상태를 결정합니다.', en: 'Beware of overeating or spicy foods today. Your Aries impulsive instinct appears in eating too, making it easy to choose overeating or spicy foods, so eating slowly and with restraint to avoid burdening the digestive system is important. Today\'s food choices determine tomorrow\'s physical condition.', zh: '今天要注意过量饮食或刺激性食物。白羊座的冲动本能也出现在饮食上，容易选择暴食或刺激性食物，所以慢慢吃并节制，不要给消化系统添加负担很重要。今天的饮食选择决定明天的身体状态。', ja: '食べ過ぎや刺激的な食べ物に気をつけるべき日です。牡羊座の衝動的な本能が食事にも現れて暴食や刺激的な食べ物を選びやすい日なので消化器に負担をかけないようゆっくり食べて節制することが重要です。今日の食事の選択が明日の体調を決めます。', es: 'Ten cuidado con comer en exceso o alimentos picantes hoy. Tu instinto impulsivo ariano aparece también en la alimentación, haciendo fácil elegir comer en exceso o alimentos picantes, así que comer despacio y con moderación para no sobrecargar el sistema digestivo es importante. Las elecciones alimentarias de hoy determinan la condición física de mañana.' },
      { ko: '급하게 움직이다 다치기 쉬운 날입니다. 화성의 에너지가 성급함을 부추기는 날이므로, 계단이나 미끄러운 바닥에서는 특히 주의가 필요합니다. 서두름을 1초만 줄여도 오늘 발생할 수 있는 작은 사고를 충분히 예방할 수 있습니다.', en: 'Easy to get hurt rushing around today. Mars\' energy encourages hastiness today, so special attention is needed on stairs and slippery floors. Even reducing haste by just 1 second is sufficient to prevent the small accidents that could occur today.', zh: '今天急忙行动容易受伤。火星的能量今天鼓励仓促，所以在楼梯或滑溜地面上特别需要注意。哪怕把匆忙减少1秒钟，就足以预防今天可能发生的小事故。', ja: '急いで動くと怪我しやすい日です。火星のエネルギーが焦りを促す日なので階段や滑りやすい床では特に注意が必要です。焦りをたった1秒でも減らすだけで今日起こりうる小さな事故を十分に予防できます。', es: 'Fácil lastimarse al apurarse hoy. La energía de Marte fomenta la prisa hoy, así que se necesita atención especial en escaleras y pisos resbaladizos. Reducir la prisa incluso solo 1 segundo es suficiente para prevenir los pequeños accidentes que podrían ocurrir hoy.' },
      { ko: '면역력이 다소 약해진 상태이므로 개인위생에 신경 쓰고 충분한 비타민을 섭취하세요. 특히 비타민 C와 D가 면역력 회복에 가장 효과적이므로, 오늘 하루 식단에 의식적으로 포함시켜보세요. 몸이 보내는 약해진 신호에 지금 바로 응답하는 것이 빠른 회복의 비결입니다.', en: 'Immunity is slightly weakened, so focus on hygiene and get enough vitamins. Vitamins C and D are most effective for immunity recovery in particular, so consciously include them in today\'s diet. Responding immediately to the weakened signals your body sends is the secret to fast recovery.', zh: '免疫力略有下降，所以注意个人卫生并摄取充足维生素。特别是维生素C和D对免疫力恢复最有效，所以今天有意识地纳入饮食。立刻回应身体发出的衰弱信号是快速恢复的秘诀。', ja: '免疫力がやや弱まった状態なので個人衛生に気を配り十分なビタミンを摂取してください。特にビタミンCとDが免疫力回復に最も効果的なので今日の食事に意識的に含めてみてください。体が送る弱まったシグナルに今すぐ応えることが早い回復の秘訣です。', es: 'La inmunidad está algo debilitada, así que enfócate en la higiene y toma vitaminas suficientes. Las vitaminas C y D son las más efectivas para la recuperación de la inmunidad en particular, así que inclúyelas conscientemente en la dieta de hoy. Responder inmediatamente a las señales debilitadas que envía tu cuerpo es el secreto para una recuperación rápida.' },
      { ko: '눈과 머리 부위에 긴장이 집중되는 날입니다. 장시간 화면 응시를 피하고 눈을 자주 쉬게 해주면, 두통이나 시야 피로를 미리 방지할 수 있습니다. 눈 건강은 몸 전체 컨디션의 바로미터임을 기억하고 오늘 특별히 눈을 돌봐주세요.', en: 'Tension concentrates in eyes and head today. Avoiding prolonged screen time and letting your eyes rest frequently prevents headaches and visual fatigue in advance. Remember that eye health is a barometer of your whole body condition and take special care of your eyes today.', zh: '今天紧张集中在眼睛和头部。避免长时间盯着屏幕，经常让眼睛休息，可以提前预防头痛或视觉疲劳。记住眼睛健康是整体身体状态的晴雨表，今天特别照顾好眼睛。', ja: '目と頭の部位に緊張が集中する日です。長時間の画面注視を避けて目を頻繁に休ませれば頭痛や視野の疲れをあらかじめ防ぐことができます。目の健康が全身のコンディションのバロメーターであることを覚えて今日特別に目を大切にしてください。', es: 'La tensión se concentra en ojos y cabeza hoy. Evitar el tiempo prolongado frente a pantallas y dejar que tus ojos descansen frecuentemente previene los dolores de cabeza y la fatiga visual de antemano. Recuerda que la salud ocular es un barómetro de toda tu condición corporal y cuida especialmente tus ojos hoy.' },
      { ko: '수면 부족이 전체 컨디션을 크게 망칠 수 있는 날입니다. 양자리의 에너지가 어떤 상황에서도 버티게 해주지만, 오늘만큼은 그 의지력에 기대지 말고 모든 일을 내려놓고 쉬어야 합니다. 오늘 쉬는 것이 내일 더 강하게 전진할 수 있는 유일한 방법입니다.', en: 'Sleep deprivation can greatly ruin your overall condition today. Aries energy makes you endure any situation, but today especially, don\'t rely on that willpower—let everything go and rest. Resting today is the only way to advance stronger tomorrow.', zh: '今天睡眠不足可能严重破坏整体状态。白羊座的能量在任何情况下都能支撑你坚持，但今天尤其不要依赖那种意志力，放下一切好好休息。今天休息是明天能更强劲前进的唯一方法。', ja: '睡眠不足が全体のコンディションを大きく台無しにする可能性がある日です。牡羊座のエネルギーがどんな状況でも持ちこたえさせてくれますが今日だけはその意志力に頼らずすべてを置いて休む必要があります。今日休むことが明日より強く前進できる唯一の方法です。', es: 'La falta de sueño puede arruinar enormemente tu condición general hoy. La energía de Aries te hace resistir cualquier situación, pero hoy especialmente, no te apoyes en esa fuerza de voluntad—suelta todo y descansa. Descansar hoy es la única manera de avanzar más fuerte mañana.' },
      { ko: '만성적인 통증이나 불편함이 있다면 더 이상 방치하지 마세요. 양자리는 고통을 참고 전진하는 경향이 있지만, 오늘은 그 신호를 무시하지 말고 전문의 상담을 받아보는 것이 진정한 용기입니다. 몸이 보내는 경고를 지금 듣지 않으면 나중에 더 큰 대가를 치를 수 있습니다.', en: 'If you have chronic pain or discomfort, don\'t ignore it any longer. Aries tends to endure pain and push forward, but today, listening to that signal rather than ignoring it and consulting a specialist is true courage. Not listening to your body\'s warnings now may cost a much greater price later.', zh: '如果有慢性疼痛或不适，不要再放任不管了。白羊座有忍痛前进的倾向，但今天不要无视那个信号，去咨询专科医生才是真正的勇气。现在不听身体的警告，以后可能付出更大的代价。', ja: '慢性的な痛みや不快感があればこれ以上放置しないでください。牡羊座は痛みを我慢して前進する傾向がありますが今日はそのサインを無視せず専門医に相談することが本当の勇気です。体が送る警告を今聞かなければ後でより大きな代償を払う可能性があります。', es: 'Si tienes dolor crónico o malestar, no lo ignores más. Aries tiende a soportar el dolor y seguir adelante, pero hoy, escuchar esa señal en lugar de ignorarla y consultar a un especialista es el verdadero valor. No escuchar las advertencias de tu cuerpo ahora puede costar un precio mucho mayor más tarde.' },
    ],
  },
  money: {
    high: [
      { ko: '화성의 추진력이 오늘 재물 영역에 강하게 작용합니다. 새로운 수입원을 만들 기회가 바로 눈앞에 있으므로, 그 기회를 알아보는 눈과 잡는 용기만 있으면 됩니다. 오늘 발견한 기회에 작은 첫 행동을 취하면 큰 흐름이 시작됩니다.', en: 'Mars\' drive works strongly in the financial realm today. Opportunities for new income are right before your eyes, so you only need the eye to recognize them and the courage to seize them. Taking a small first action on an opportunity discovered today starts a great flow.', zh: '火星的推动力今天在财富领域强力发挥作用。创造新收入来源的机会就在眼前，只需要发现它的眼光和抓住它的勇气。今天对发现的机会采取一个小小的第一行动，大流势就此开始。', ja: '火星の推進力が今日財運の領域に強く作用します。新しい収入源を作るチャンスがすぐ目の前にあるので、そのチャンスを見抜く目と掴む勇気さえあればいいのです。今日発見したチャンスに小さな最初の行動を取れば大きな流れが始まります。', es: 'El impulso de Marte actúa fuertemente en el área financiera hoy. Las oportunidades para nuevos ingresos están justo ante tus ojos, así que solo necesitas el ojo para reconocerlas y el valor para tomarlas. Tomar una pequeña primera acción sobre una oportunidad descubierta hoy inicia un gran flujo.' },
      { ko: '과감한 투자 결정이 좋은 결과를 가져올 수 있는 날입니다. 단, 확신이 있을 때만 실행하는 것이 원칙이며, 두려움이 아닌 분석에 기반한 결정이어야 합니다. 화성의 에너지가 결단을 지원하는 오늘, 준비된 자에게 가장 강한 운이 찾아옵니다.', en: 'Bold investment decisions can bring good results today. However, the principle is to execute only when certain, and decisions must be based on analysis, not fear. Today, with Mars energy supporting decisiveness, the strongest luck comes to those who are prepared.', zh: '今天大胆的投资决定可能带来好结果。但只有确信时才执行是原则，决定必须基于分析而非恐惧。火星能量支持果断的今天，最强的运气来到有准备的人身上。', ja: '大胆な投資決定が良い結果をもたらす可能性がある日です。ただし確信がある時のみ実行することが原則であり恐れではなく分析に基づく決定でなければなりません。火星のエネルギーが決断を支援する今日、準備できた者に最も強い運が訪れます。', es: 'Las decisiones de inversión audaces pueden traer buenos resultados hoy. Sin embargo, el principio es ejecutar solo cuando estés seguro/a, y las decisiones deben basarse en análisis, no en miedo. Hoy, con la energía de Marte apoyando la decisión, la suerte más fuerte llega a quienes están preparados.' },
      { ko: '그동안의 노력이 금전적 보상으로 돌아오는 시기입니다. 눈에 보이지 않아도 쌓여온 노력의 기록들이 오늘 수치로 환산되는 순간을 맞이합니다. 성과급이나 보너스를 기대하며 평소의 노력이 얼마나 가치 있는지 오늘 확인하세요.', en: 'Your accumulated efforts are returning as financial rewards now. The records of effort built up even when invisible meet their moment of being converted to numbers today. Expect bonuses and confirm today just how valuable your consistent efforts are.', zh: '一直以来的努力现在以金钱回报的形式归来。即使看不见也积累的努力记录，今天迎来换算成数字的时刻。期待绩效奖金或奖励，今天确认平时的努力有多大价值。', ja: 'これまでの努力が金銭的な報酬として返ってくる時期です。見えなくても積み重なってきた努力の記録が今日数値に換算される瞬間を迎えます。成果給やボーナスに期待しながら日頃の努力がいかに価値があるか今日確認してください。', es: 'Tus esfuerzos acumulados están regresando ahora como recompensas financieras. Los registros de esfuerzo acumulados incluso cuando son invisibles se encuentran con su momento de ser convertidos a números hoy. Espera bonificaciones y confirma hoy cuán valiosos son tus esfuerzos constantes.' },
      { ko: '사업 확장이나 부업 시작에 유리한 에너지가 오늘 강하게 흐릅니다. 행동으로 옮기기에 이보다 좋은 날이 없으며, 시작의 두려움이 가장 작고 성공의 가능성이 가장 높은 타이밍입니다. 오늘 첫 번째 구체적 행동 하나를 실행에 옮기면 나머지가 따라옵니다.', en: 'Favorable energy flows strongly today for business expansion or starting side gigs. There\'s no better day to take action, and it\'s the timing when fear of starting is smallest and probability of success is highest. Execute one specific first action today and the rest will follow.', zh: '今天有利于业务扩展或开始副业的能量强力流动。没有比这更好的行动日子，是开始的恐惧最小、成功可能性最高的时机。今天付诸行动第一个具体行动，其余会随之而来。', ja: '事業拡大や副業開始に有利なエネルギーが今日強く流れています。行動に移すのにこれ以上良い日はなく始まりの恐れが最も小さく成功の可能性が最も高いタイミングです。今日最初の具体的な行動一つを実行に移せば残りがついてきます。', es: 'Fluye energía favorable fuertemente hoy para expandir negocios o iniciar proyectos secundarios. No hay mejor día para actuar, y es el momento cuando el miedo a comenzar es menor y la probabilidad de éxito es mayor. Ejecuta una primera acción específica hoy y el resto seguirá.' },
      { ko: '금전적 협상에서 유리한 고지를 점할 수 있습니다. 자신의 가치를 당당하게 주장할 때, 상대방은 그 확신에 자연스럽게 이끌리기 때문에 협상 테이블에서 당신이 먼저 말하는 사람이 되세요. 오늘 주장한 만큼 보상받을 수 있습니다.', en: 'You can gain advantage in financial negotiations today. When you assert your value confidently, the other party is naturally drawn to that conviction—so be the first to speak at the negotiating table. Today you can be rewarded as much as you assert.', zh: '今天可以在金钱谈判中占据有利地位。当你自信地主张自己的价值时，对方会自然地被那份确信所吸引，所以在谈判桌上做第一个发言的人。今天主张多少就能得到多少回报。', ja: '金銭的な交渉で有利な立場を占めることができます。自分の価値を堂々と主張する時相手はその確信に自然と引き寄せられるので交渉テーブルで最初に話す人になってください。今日主張した分だけ報われることができます。', es: 'Puedes ganar ventaja en negociaciones financieras hoy. Cuando afirmas tu valor con confianza, la otra parte se siente naturalmente atraída por esa convicción—así que sé el primero/la primera en hablar en la mesa de negociación. Hoy puedes ser recompensado/a tanto como afirmes.' },
      { ko: '예상치 못한 곳에서 재물 운이 들어오는 날입니다. 우주는 항상 예상치 못한 경로로 풍요를 보내기 때문에, 열린 마음으로 기회를 포착하면 평소에는 주목하지 않던 곳에서 뜻밖의 수입이 생길 수 있습니다. 오늘 만나는 모든 인연이 잠재적 기회임을 기억하세요.', en: 'Financial luck comes from unexpected places today. The universe always sends abundance through unexpected paths, so capturing opportunities with an open mind may bring unexpected income from places you usually don\'t notice. Remember that every connection you make today is a potential opportunity.', zh: '今天财运从意想不到的地方进入。宇宙总是通过意想不到的路径送来丰盛，所以以开放的心态捕捉机会，可能从平时不注意的地方产生意外的收入。记住今天遇到的所有缘分都是潜在的机会。', ja: '予想外の場所から財運が入ってくる日です。宇宙はいつも予想外の経路で豊かさを送るので、オープンな心で機会を捉えれば普段は注目しない場所から思いがけない収入が生まれる可能性があります。今日出会う全ての縁が潜在的なチャンスであることを覚えておいてください。', es: 'La suerte financiera llega de lugares inesperados hoy. El universo siempre envía abundancia a través de caminos inesperados, así que captar oportunidades con mente abierta puede traer ingresos inesperados de lugares que normalmente no notas. Recuerda que cada conexión que hagas hoy es una oportunidad potencial.' },
      { ko: '리더십을 발휘하여 팀 성과를 높이면 그에 따른 재정적 보상이 자연스럽게 뒤따릅니다. 팀 전체를 이끌어 더 큰 결과를 만들어낼 때, 당신의 기여도가 가장 명확하게 보이기 때문에 보상도 가장 확실합니다. 오늘 팀을 위해 한 발 더 나서는 것이 가장 현명한 재테크입니다.', en: 'When you boost team results through leadership, financial rewards naturally follow. When you lead the entire team to create greater results, your contribution is most clearly visible, making rewards most certain. Stepping one step further for the team today is the wisest financial investment.', zh: '发挥领导力提高团队成果，随之而来的财务回报自然跟随。当你引领整个团队创造更大结果时，你的贡献最清晰可见，回报也最确定。今天为团队多迈出一步，是最明智的理财。', ja: 'リーダーシップを発揮してチーム成果を高めればそれに伴う財政的報酬が自然についてきます。チーム全体を導いてより大きな結果を生み出す時あなたの貢献度が最も明確に見えるので報酬も最も確実です。今日チームのためにもう一歩踏み出すことが最も賢明な財テクです。', es: 'Cuando mejoras los resultados del equipo a través del liderazgo, las recompensas financieras siguen naturalmente. Cuando lideras a todo el equipo para crear resultados más grandes, tu contribución es más claramente visible, haciendo las recompensas más ciertas. Dar un paso más por el equipo hoy es la inversión financiera más sabia.' },
      { ko: '장기적으로 추진해온 재테크 계획이 드디어 결실을 맺기 시작합니다. 꾸준함의 힘이 이렇게 구체적인 숫자로 나타나는 것을 오늘 느껴보세요. 이 경험이 다음 재테크 계획을 더 강한 의지로 추진할 수 있는 가장 강력한 동기가 됩니다.', en: 'Long-term financial plans you\'ve been pursuing finally begin bearing fruit. Feel today how the power of consistency manifests as concrete numbers like this. This experience becomes the most powerful motivation to pursue the next financial plan with stronger will.', zh: '长期推进的理财计划终于开始结出果实。今天感受一下坚持的力量如何以具体数字这样显现。这种体验成为用更强意志推进下一个理财计划的最强动力。', ja: '長期的に推進してきた財テク計画がついに実を結び始めます。着実さの力がこのように具体的な数字として現れるのを今日感じてみてください。この体験が次の財テク計画をより強い意志で推進できる最も強力なモチベーションとなります。', es: 'Los planes financieros a largo plazo que has estado persiguiendo finalmente comienzan a dar frutos. Siente hoy cómo el poder de la constancia se manifiesta como números concretos así. Esta experiencia se convierte en la motivación más poderosa para perseguir el próximo plan financiero con voluntad más fuerte.' },
      { ko: '오늘 결정한 재무 계획은 미래에 큰 자산이 됩니다. 저축이나 투자 계획을 구체적인 숫자와 날짜로 구체화하면, 그 계획이 실현될 가능성이 훨씬 높아집니다. 오늘 10분만 투자해 재무 계획을 종이에 써내려가세요.', en: 'Financial plans decided today become great future assets. When you solidify savings or investment plans with specific numbers and dates, the probability of those plans being realized increases significantly. Invest just 10 minutes today to write your financial plan on paper.', zh: '今天决定的财务计划将成为未来的重要资产。用具体数字和日期将储蓄或投资计划具体化，那个计划实现的可能性会大幅提高。今天只投资10分钟，把财务计划写在纸上。', ja: '今日決めた財務計画は未来の大きな資産になります。貯蓄や投資計画を具体的な数字と日付で具体化すれば、その計画が実現される可能性がずっと高まります。今日10分だけ投資して財務計画を紙に書き出してみてください。', es: 'Los planes financieros decididos hoy se convierten en grandes activos futuros. Cuando solidificas planes de ahorro o inversión con números y fechas específicas, la probabilidad de que esos planes se realicen aumenta significativamente. Invierte solo 10 minutos hoy para escribir tu plan financiero en papel.' },
      { ko: '양자리의 개척 정신이 오늘 새로운 수익 모델을 발견하게 해줍니다. 남들이 아직 보지 못한 시장의 빈 틈을 먼저 발견하는 것이 양자리의 가장 강력한 재능이므로, 창의적으로 접근하면 완전히 새로운 방향에서 수익 기회를 찾게 됩니다. 오늘 떠오르는 아이디어를 즉시 기록해두세요.', en: 'Your Aries pioneering spirit discovers new revenue models today. Finding the empty spaces in markets that others haven\'t seen yet is Aries\' most powerful talent, so approaching creatively will find income opportunities from completely new directions. Record immediately any ideas that come to you today.', zh: '白羊座的开拓精神今天让你发现新的收益模式。在别人尚未看见的市场空白中率先发现，是白羊座最强大的才能，所以创造性地接近将从全新方向发现收入机会。今天浮现的想法立刻记录下来。', ja: '牡羊座の開拓精神が今日新しい収益モデルを発見させてくれます。他の人がまだ見ていない市場の空白をいち早く見つけることが牡羊座の最も強力な才能なので創造的にアプローチすれば全く新しい方向から収益機会を見つけることになります。今日浮かんだアイデアをすぐ記録しておいてください。', es: 'Tu espíritu pionero ariano descubre nuevos modelos de ingresos hoy. Encontrar los espacios vacíos en mercados que otros aún no han visto es el talento más poderoso de Aries, así que acercarse creativamente encontrará oportunidades de ingresos desde direcciones completamente nuevas. Registra inmediatamente cualquier idea que se te ocurra hoy.' },
    ],
    medium: [
      { ko: '안정적인 금전 흐름이 잘 유지되고 있는 날입니다. 현재의 재무 상태를 점검하고 계획을 미세하게 조정하면, 지금의 안정이 다음 도약의 발판이 됩니다. 오늘의 재무 점검 15분이 다음 달 더 나은 숫자를 만들어냅니다.', en: 'Stable cash flow is well maintained today. Reviewing your financial status and fine-tuning plans makes today\'s stability the foundation for the next leap. 15 minutes of financial review today creates better numbers next month.', zh: '今天稳定的资金流维持得很好。检查当前财务状况并微调计划，当下的稳定成为下一次跃进的基础。今天15分钟的财务检查创造下个月更好的数字。', ja: '安定的な金銭の流れがうまく維持されている日です。現在の財務状態を点検し計画を微調整すれば今の安定が次の飛躍の足がかりになります。今日の財務点検15分が来月のより良い数字を生み出します。', es: 'El flujo de efectivo estable se mantiene bien hoy. Revisar tu estado financiero y ajustar finamente los planes convierte la estabilidad de hoy en la base para el próximo salto. 15 minutos de revisión financiera hoy crea mejores números el próximo mes.' },
      { ko: '큰 지출보다 작은 절약의 실천이 오늘 더 중요합니다. 불필요한 구독 서비스를 정리하면, 매달 새어나가는 돈이 쌓여 연말에는 상당한 금액이 됩니다. 오늘 5분을 투자해 구독 목록을 확인하는 것이 가장 간단한 재테크입니다.', en: 'Practicing small savings matters more than big spending today. Canceling unnecessary subscriptions means the money leaking out monthly accumulates to a substantial amount by year-end. Investing 5 minutes today to check subscription lists is the simplest financial investment.', zh: '今天实践小节约比大支出更重要。整理不必要的订阅服务，每月流失的钱积累到年底会是相当可观的金额。今天投资5分钟确认订阅列表，是最简单的理财。', ja: '大きな支出より小さな節約の実践が今日より重要です。不要なサブスクリプションを整理すれば毎月漏れていくお金が積み重なって年末にはかなりの金額になります。今日5分投資して購読リストを確認することが最も簡単な財テクです。', es: 'Practicar pequeños ahorros importa más que los grandes gastos hoy. Cancelar suscripciones innecesarias significa que el dinero que se escapa mensualmente se acumula hasta una cantidad sustancial a fin de año. Invertir 5 minutos hoy para revisar la lista de suscripciones es la inversión financiera más simple.' },
      { ko: '수입과 지출의 균형을 오늘 확인해보세요. 가계부 작성이 금전 관리의 첫걸음이며, 숫자를 직면하는 용기가 재정 자유의 시작점입니다. 오늘 처음 시작하는 가계부의 첫 줄이 당신의 재정 역사를 바꿀 수 있습니다.', en: 'Check the balance between income and expenses today. Budgeting is the first step in financial management, and the courage to face the numbers is the starting point of financial freedom. The first line of a budget you start for the first time today can change your financial history.', zh: '今天确认收支平衡。记账是理财的第一步，面对数字的勇气是财务自由的起点。今天第一次开始记账的第一行，可以改变你的财务历史。', ja: '収入と支出のバランスを今日確認してみてください。家計簿を書くことが金銭管理の第一歩であり数字に向き合う勇気が財政的自由の出発点です。今日初めて始める家計簿の最初の一行があなたの財政の歴史を変えることができます。', es: 'Verifica hoy el equilibrio entre ingresos y gastos. El presupuesto es el primer paso en la gestión financiera, y el valor de enfrentarse a los números es el punto de partida de la libertad financiera. La primera línea de un presupuesto que empiezas por primera vez hoy puede cambiar tu historia financiera.' },
      { ko: '투자에 대한 판단은 좀 더 정보를 모은 후 내리는 것이 현명합니다. 서두를 필요가 없으며, 좋은 투자 기회는 정보가 충분할 때 결정해도 늦지 않습니다. 오늘 하나의 투자 관련 자료를 더 읽어보는 것이 미래의 더 나은 결정으로 이어집니다.', en: 'It\'s wiser to gather more information before investment decisions. There\'s no need to rush—good investment opportunities aren\'t too late to decide when you have sufficient information. Reading one more investment-related resource today leads to better decisions in the future.', zh: '投资判断多收集信息后再做更明智。不需要着急，好的投资机会信息充足时再决定也不迟。今天再读一篇投资相关资料，会带来未来更好的决定。', ja: '投資に対する判断はもう少し情報を集めてから下すのが賢明です。急ぐ必要はなく良い投資機会は情報が十分な時に決めても遅くはありません。今日一つの投資関連資料をもう読むことが未来のより良い決断につながります。', es: 'Es más sabio reunir más información antes de decisiones de inversión. No hay prisa—las buenas oportunidades de inversión no son demasiado tarde para decidir cuando tienes información suficiente. Leer un recurso más relacionado con inversiones hoy lleva a mejores decisiones en el futuro.' },
      { ko: '일상적인 소비를 점검하고 개선 포인트를 찾아보세요. 작은 변화들이 모여 큰 차이를 만드는 것처럼, 오늘 발견한 하나의 개선점이 한 달 후 재정 상태를 눈에 띄게 변화시킬 수 있습니다. 지출 분석에 10분을 쓰는 것이 가장 수익률 높은 시간 투자입니다.', en: 'Review daily spending and find areas to improve. Just as small changes accumulate to create big differences, one improvement point discovered today can noticeably change your financial state a month later. Spending 10 minutes on expense analysis is the highest-return time investment.', zh: '检查日常消费并找出改进点。就像小变化积累成大差异，今天发现的一个改进点可以在一个月后明显改变财务状况。在支出分析上花10分钟是回报率最高的时间投资。', ja: '日常的な消費を点検し改善ポイントを探してみてください。小さな変化が集まって大きな違いを生むように今日発見した一つの改善点が一ヶ月後の財政状態を目に見えて変化させることができます。支出分析に10分を費やすことが最も収益率の高い時間投資です。', es: 'Revisa los gastos diarios y encuentra áreas de mejora. Así como los pequeños cambios se acumulan para crear grandes diferencias, un punto de mejora descubierto hoy puede cambiar notablemente tu estado financiero un mes después. Gastar 10 minutos en análisis de gastos es la inversión de tiempo con mayor retorno.' },
      { ko: '재정 목표를 구체적인 숫자로 설정하면 달성 가능성이 크게 높아집니다. "돈을 모으겠다"가 아니라 "6개월 후까지 100만 원을 모으겠다"처럼 구체적인 계획을 세워보세요. 오늘 그 계획을 종이에 쓰는 것이 목표를 현실로 만드는 첫 번째 단계입니다.', en: 'Setting financial goals with specific numbers greatly increases achievement probability. Don\'t say "I\'ll save money" but plan concretely like "I\'ll save a million won in 6 months." Writing that plan on paper today is the first step to making goals reality.', zh: '用具体数字设定财务目标会大幅提高达成可能性。不是"要存钱"，而是像"6个月内要存10万元"这样制定具体计划。今天把那个计划写在纸上，是把目标变为现实的第一步。', ja: '財政目標を具体的な数字で設定すれば達成可能性が大きく高まります。「お金を貯める」ではなく「6ヶ月後までに100万円を貯める」のように具体的な計画を立ててみてください。今日その計画を紙に書くことが目標を現実にする第一段階です。', es: 'Establecer metas financieras con números específicos aumenta enormemente la probabilidad de logro. No digas "voy a ahorrar dinero" sino planifica concretamente como "voy a ahorrar un millón en 6 meses." Escribir ese plan en papel hoy es el primer paso para hacer las metas realidad.' },
      { ko: '타인에게 금전적 도움을 요청하기보다 스스로 해결책을 찾는 것이 더 나은 결과를 냅니다. 의존보다 자립이 장기적으로 더 강한 재정 기반을 만들며, 스스로 해결하는 과정에서 더 중요한 재정 능력이 키워집니다. 오늘 혼자 해결해낸 경험이 내일의 자신감이 됩니다.', en: 'Finding solutions yourself brings better results than asking others for financial help. Independence rather than dependence builds a stronger financial foundation long-term, and in the process of solving on your own, more important financial capability develops. The experience of solving alone today becomes tomorrow\'s confidence.', zh: '自己找解决办法比向他人请求经济帮助带来更好的结果。独立比依赖长期建立更强的财务基础，在自己解决的过程中培养更重要的财务能力。今天独自解决的经历成为明天的自信。', ja: '他人に金銭的な助けを求めるより自分で解決策を探す方がより良い結果を生みます。依存より自立が長期的により強い財政基盤を作り自分で解決する過程でより重要な財政能力が育ちます。今日一人で解決できた経験が明日の自信となります。', es: 'Encontrar soluciones propias trae mejores resultados que pedir ayuda financiera a otros. La independencia en lugar de la dependencia construye una base financiera más fuerte a largo plazo, y en el proceso de resolverlo por tu cuenta, se desarrollan capacidades financieras más importantes. La experiencia de resolver solo hoy se convierte en la confianza de mañana.' },
      { ko: '급여나 수입에 만족하며 현재에 감사하는 마음이 더 큰 풍요를 끌어당깁니다. 부족함에 집중하면 부족함이 계속 보이지만, 충분함에 집중할 때 새로운 기회가 눈에 들어오기 시작합니다. 오늘 재정적으로 감사한 세 가지를 찾아 적어보세요.', en: 'Being grateful for your income attracts greater abundance. When you focus on lack, lack keeps appearing, but when you focus on sufficiency, new opportunities begin to come into view. Find and write three things you\'re financially grateful for today.', zh: '对工资或收入满意并感恩现在会吸引更大的富裕。专注于不足，不足就会一直出现；专注于充足时，新机会开始映入眼帘。今天找出三件财务上感恩的事写下来。', ja: '給与や収入に満足し現在に感謝する気持ちがより大きな豊かさを引き寄せます。不足に集中すれば不足が見え続けますが充足に集中する時新しい機会が目に入り始めます。今日財政的に感謝する3つのことを見つけて書いてみてください。', es: 'Estar agradecido/a por tus ingresos atrae mayor abundancia. Cuando te enfocas en la escasez, la escasez sigue apareciendo, pero cuando te enfocas en la suficiencia, nuevas oportunidades comienzan a aparecer. Encuentra y escribe tres cosas por las que estás financieramente agradecido/a hoy.' },
      { ko: '평소 소비 습관을 돌아보고 충동구매 패턴이 있다면 개선 방안을 마련해보세요. 양자리의 충동적 본능이 장바구니를 채우는 일에도 발동된다면, 구매 전 24시간 대기 규칙을 하나의 방어막으로 활용해보세요. 작은 규칙 하나가 매달 지갑을 지킬 수 있습니다.', en: 'Reflect on spending habits and address impulse buying patterns if any. If your Aries impulsive instinct also triggers filling shopping carts, try using a 24-hour waiting rule before purchasing as a defense. One small rule can protect your wallet every month.', zh: '回顾平时的消费习惯，如果有冲动购买模式就想办法改善。如果白羊座的冲动本能也在填满购物车时发动，试试把购买前等待24小时的规则作为一道防线。一个小规则每个月都能保护你的钱包。', ja: '普段の消費習慣を振り返り衝動買いのパターンがあれば改善策を考えてみてください。牡羊座の衝動的な本能がショッピングカートを満たすことにも発動するなら購入前24時間待機ルールを一つの防御として活用してみてください。小さなルール一つが毎月財布を守ることができます。', es: 'Reflexiona sobre los hábitos de gasto y aborda los patrones de compra impulsiva si los hay. Si tu instinto impulsivo ariano también se activa al llenar carritos de compras, prueba usar una regla de espera de 24 horas antes de comprar como defensa. Una pequeña regla puede proteger tu billetera cada mes.' },
      { ko: '재테크 공부에 시간을 투자하면 향후 큰 도움이 됩니다. 금융 지식은 가장 수익률이 높은 투자이며, 오늘 배운 한 가지 개념이 미래의 더 나은 결정으로 이어집니다. 관련 서적이나 강좌를 찾아보는 것이 오늘 가장 현명한 시간 활용입니다.', en: 'Investing time in financial literacy pays off big later. Financial knowledge is the highest-return investment, and one concept learned today leads to better decisions in the future. Finding relevant books or courses is the wisest use of time today.', zh: '花时间学习理财将来会有大帮助。金融知识是回报率最高的投资，今天学到的一个概念带来未来更好的决定。找找相关书籍或课程，是今天最明智的时间利用。', ja: '財テクの勉強に時間を投資すれば今後大きな助けになります。金融知識は最も収益率の高い投資であり今日学んだ一つの概念が未来のより良い決断につながります。関連書籍や講座を探すことが今日最も賢明な時間の活用です。', es: 'Invertir tiempo en educación financiera rinde mucho después. El conocimiento financiero es la inversión con mayor retorno, y un concepto aprendido hoy lleva a mejores decisiones en el futuro. Encontrar libros o cursos relevantes es el uso más sabio del tiempo hoy.' },
    ],
    low: [
      { ko: '충동구매의 유혹이 특히 강한 날입니다. 화성의 에너지가 즉각적인 보상을 원하게 만들기 때문에, 지갑을 열기 전에 "이것이 없으면 삶에 무언가 빠지는가?"라고 자문해보세요. 그 질문이 불필요한 소비를 막아주는 가장 강력한 방어막입니다.', en: 'Impulse buying temptation is especially strong today. Mars\' energy creates a desire for immediate rewards, so before opening your wallet, ask yourself "Does my life lack something without this?" That question is the most powerful defense against unnecessary spending.', zh: '今天冲动购买的诱惑特别强。火星的能量让你渴望即时回报，所以打开钱包前问自己"没有这个我的生活会缺少什么？"那个问题是阻止不必要消费的最强防线。', ja: '衝動買いの誘惑が特に強い日です。火星のエネルギーが即時の報酬を求めさせるので財布を開く前に「これがなければ人生に何か欠けるのか？」と自問してみてください。その質問が不要な消費を防ぐ最も強力な防御壁です。', es: 'La tentación de compra impulsiva es especialmente fuerte hoy. La energía de Marte crea el deseo de recompensas inmediatas, así que antes de abrir tu billetera, pregúntate "¿Le falta algo a mi vida sin esto?" Esa pregunta es la defensa más poderosa contra el gasto innecesario.' },
      { ko: '무리한 투자나 도박성 지출을 반드시 삼가야 하는 날입니다. 오늘의 손실은 평소보다 회복하기 훨씬 어려울 수 있으며, 한 번의 잘못된 결정이 수개월의 절약을 무너뜨릴 수 있습니다. 지금 당신이 가진 것을 지키는 것이 가장 강력한 재테크입니다.', en: 'You must absolutely avoid risky investments or gambling expenses today. Today\'s losses may be much harder to recover from than usual, and one wrong decision can undo months of saving. Protecting what you currently have is the most powerful financial strategy.', zh: '今天必须坚决避免冒险投资或赌博性支出。今天的损失可能比平时难以恢复得多，一次错误决定可能摧毁数月的节省。守住现在拥有的是最强大的理财。', ja: '無理な投資やギャンブル性の支出を必ず控えるべき日です。今日の損失は普段より回復が遥かに難しい可能性があり一度の誤った決定が数ヶ月の節約を崩すことがあります。今あなたが持っているものを守ることが最も強力な財テクです。', es: 'Debes evitar absolutamente las inversiones arriesgadas o los gastos de apuesta hoy. Las pérdidas de hoy pueden ser mucho más difíciles de recuperar que de costumbre, y una decisión equivocada puede deshacer meses de ahorro. Proteger lo que tienes actualmente es la estrategia financiera más poderosa.' },
      { ko: '예상치 못한 지출이 발생할 수 있으니 비상금을 미리 확인하고 여유 자금을 확보해두세요. 비상금은 인생의 안전망이며, 그 존재가 당신을 나쁜 결정에서 보호합니다. 오늘 비상금 잔액을 확인하고 부족하다면 적립 계획을 세워보세요.', en: 'Unexpected expenses may arise, so check emergency funds in advance and secure reserves. Emergency funds are life\'s safety net, and their existence protects you from bad decisions. Check your emergency fund balance today and make a plan to build it up if insufficient.', zh: '可能发生意外支出，所以提前确认应急资金并确保有备用资金。应急资金是人生的安全网，它的存在保护你免于错误决定。今天确认应急资金余额，如果不足就制定积累计划。', ja: '予想外の支出が発生する可能性があるので非常資金をあらかじめ確認し余裕資金を確保しておいてください。非常資金は人生の安全網でありその存在があなたを悪い決断から守ります。今日非常資金の残高を確認して不足していれば積立計画を立ててみてください。', es: 'Podrían surgir gastos inesperados, así que verifica los fondos de emergencia con anticipación y asegura reservas. Los fondos de emergencia son la red de seguridad de la vida, y su existencia te protege de malas decisiones. Verifica el saldo de tu fondo de emergencia hoy y haz un plan para construirlo si es insuficiente.' },
      { ko: '금전적 계약이나 서류에 서명하기 전에 꼼꼼히 내용을 확인해야 합니다. 양자리의 빠른 본능이 세부 사항을 건너뛰게 만들 수 있으므로, 오늘만큼은 작은 글씨까지 읽고 이해하는 시간을 가지세요. 숨은 함정은 항상 세부 사항 속에 있습니다.', en: 'Check financial contract contents carefully before signing today. Your Aries quick instinct may cause you to skip details, so take time today to read and understand even the fine print. Hidden traps are always in the details.', zh: '今天签署金融合同或文件前仔细确认内容。白羊座快速的本能可能让你跳过细节，所以今天花时间阅读并理解即使是小字的部分。隐藏的陷阱总在细节中。', ja: '金銭的な契約や書類にサインする前に内容をしっかり確認しなければなりません。牡羊座の素早い本能が詳細を飛ばさせる可能性があるので今日だけは細かい文字まで読んで理解する時間を持ってください。隠れた罠はいつも詳細の中にあります。', es: 'Revisa cuidadosamente el contenido de contratos financieros antes de firmar hoy. Tu instinto rápido ariano puede hacer que te saltes los detalles, así que tómate tiempo hoy para leer y entender incluso la letra pequeña. Las trampas ocultas siempre están en los detalles.' },
      { ko: '타인에게 큰 금액을 빌려주는 것은 오늘 삼가세요. 돈 문제가 가장 소중한 관계를 해치는 경우가 많으며, 대여보다 선물이 관계를 더 건강하게 지킵니다. 도움을 주고 싶다면 돌려받을 수 있는 금액 안에서 결정하세요.', en: 'Avoid lending large amounts to others today. Money issues often harm the most precious relationships, and giving rather than lending keeps relationships healthier. If you want to help, decide within an amount you can receive back.', zh: '今天避免借大笔钱给他人。金钱问题常常伤害最宝贵的关系，给予比借贷更能保持关系健康。如果想帮忙，在能收回的金额内决定。', ja: '他人に大きな金額を貸すのを今日は控えてください。お金の問題が最も大切な関係を傷つけることが多く貸し出しより贈り物の方が関係をより健全に保ちます。助けたいなら返してもらえる金額の範囲内で決めてください。', es: 'Evita prestar grandes cantidades a otros hoy. Los problemas de dinero a menudo dañan las relaciones más preciosas, y dar en lugar de prestar mantiene las relaciones más saludables. Si quieres ayudar, decide dentro de una cantidad que puedas recibir de vuelta.' },
      { ko: '화가 나서 돈을 쓰는 분노 소비를 조심해야 하는 날입니다. 감정과 재무를 분리하는 것이 가장 중요한 재정 습관이며, 쇼핑이 감정을 잠시 진정시키는 것처럼 느껴지지만 나중에 더 큰 스트레스를 만듭니다. 감정이 격할 때 지갑 대신 일기를 펼치세요.', en: 'Beware of anger spending today. Separating emotions from finances is the most important financial habit, and while shopping may feel like it temporarily soothes emotions, it creates greater stress later. When emotions run high, open a journal instead of your wallet.', zh: '今天要小心因愤怒而花钱的报复性消费。将情绪与财务分开是最重要的财务习惯，购物虽然感觉能暂时平息情绪，但之后会带来更大的压力。情绪激动时，打开日记而不是钱包。', ja: '怒りでお金を使う感情消費に気をつけるべき日です。感情と財務を分離することが最も重要な財政習慣であり買い物が感情を一時的に落ち着かせるように感じても後でより大きなストレスを生みます。感情が高ぶった時は財布の代わりに日記を開いてください。', es: 'Ten cuidado con el gasto por enojo hoy. Separar las emociones de las finanzas es el hábito financiero más importante, y aunque las compras puedan sentirse como si calmaran temporalmente las emociones, crean mayor estrés después. Cuando las emociones se intensifiquen, abre un diario en lugar de tu billetera.' },
      { ko: '급한 마음에 성급하게 결정한 재무 계획은 손실로 이어질 수 있습니다. 양자리의 빠른 결정 능력은 일상에서는 강점이지만 재무에서는 검토 시간이 필요합니다. 전문가 상담을 먼저 받거나 최소 하루를 기다리는 것이 오늘의 현명한 원칙입니다.', en: 'Hasty financial plans may lead to losses. Your Aries quick decision ability is a strength in daily life but finances need review time. Getting expert consultation first or waiting at least one day is today\'s wise principle.', zh: '急忙做出的财务计划可能导致损失。白羊座快速决策能力在日常生活是优势，但财务需要审查时间。先咨询专家或至少等一天，是今天明智的原则。', ja: '焦って急いで決めた財務計画は損失につながる可能性があります。牡羊座の素早い決断能力は日常では強みですが財務では検討時間が必要です。専門家に相談してからか最低一日待つことが今日の賢明な原則です。', es: 'Los planes financieros apresurados pueden llevar a pérdidas. Tu capacidad de decisión rápida ariana es una fortaleza en la vida diaria pero las finanzas necesitan tiempo de revisión. Obtener consulta experta primero o esperar al menos un día es el principio sabio de hoy.' },
      { ko: '고가의 물건 구입은 오늘이 아닌 다른 날로 미루는 것이 현명합니다. 오늘의 원하는 감정이 내일도 같은 강도로 지속된다면 그때 구입하면 됩니다. 냉각 기간을 통해 충동이 식은 후에도 필요하다면 그것은 진정으로 가치 있는 구매입니다.', en: 'Postpone expensive purchases to another day today. If the desire feeling remains with the same intensity tomorrow, buy it then. After the cooling-off period extinguishes the impulse, if still needed, it\'s truly a worthwhile purchase.', zh: '今天高价物品的购买推迟到其他日子更明智。如果今天想要的感觉明天仍以同样的强度持续，那时再购买。经过冷静期冲动消退后仍需要，那就是真正有价值的购买。', ja: '高価なものの購入は今日ではなく別の日に延期するのが賢明です。今日欲しいという感情が明日も同じ強度で続くならその時購入すればいいです。冷却期間を経て衝動が冷めた後でも必要なら、それは本当に価値ある購買です。', es: 'Pospón las compras costosas para otro día hoy. Si el sentimiento de deseo persiste con la misma intensidad mañana, cómpralo entonces. Después de que el período de enfriamiento extinga el impulso, si aún se necesita, es verdaderamente una compra que vale la pena.' },
      { ko: '친구나 지인의 투자 권유에 쉽게 넘어가지 마세요. 좋은 투자는 권유를 받기 전에 스스로 찾는 것이며, 권유 받은 투자는 이미 늦은 경우가 많습니다. 스스로 충분히 조사한 후 판단하면 후회 없는 결정을 내릴 수 있습니다.', en: 'Don\'t easily fall for friends\' investment advice. Good investments are ones you find yourself before being advised, and advised investments are often already late. Research thoroughly yourself before deciding and you can make decisions without regret.', zh: '不要轻易被朋友或熟人的投资建议打动。好的投资是在被建议前自己发现的，被建议的投资往往已经晚了。自己充分调查后再判断，就能做出无悔的决定。', ja: '友人や知人の投資勧誘に簡単に乗らないでください。良い投資は勧誘を受ける前に自分で見つけるものであり勧誘を受けた投資はすでに遅い場合が多いです。自分で十分に調査してから判断すれば後悔のない決定ができます。', es: 'No caigas fácilmente en los consejos de inversión de amigos. Las buenas inversiones son las que encuentras por ti mismo/a antes de ser aconsejado/a, y las inversiones aconsejadas suelen ser ya tardías. Investiga ampliamente por tu cuenta antes de decidir y podrás tomar decisiones sin arrepentimiento.' },
      { ko: '카드 사용을 최소화하고 현금 위주로 생활하면 과소비를 자연스럽게 방지할 수 있습니다. 현금은 눈에 보이기 때문에 지출이 실감되어 카드보다 훨씬 절약적으로 사용하게 됩니다. 오늘 하루만 현금으로 생활해보는 실험을 해보면 소비 패턴이 달라지는 것을 느낄 수 있습니다.', en: 'Minimizing card use and living with cash naturally prevents overspending. Because cash is visible, spending feels real and you use it far more frugally than cards. Try the experiment of living with cash for just today and you can feel your consumption pattern changing.', zh: '最小化信用卡使用，以现金为主可以自然防止过度消费。因为现金看得见，支出有实感，比信用卡省得多。试试今天一天用现金生活的实验，可以感受到消费模式的改变。', ja: 'カード使用を最小限にし現金中心で生活すれば過消費を自然に防げます。現金は目に見えるので支出が実感されてカードよりずっと節約的に使うようになります。今日一日だけ現金で生活してみる実験をしてみると消費パターンが変わるのを感じることができます。', es: 'Minimizar el uso de tarjetas y vivir con efectivo previene naturalmente el gasto excesivo. Porque el efectivo es visible, el gasto se siente real y lo usas mucho más frugalmente que las tarjetas. Prueba el experimento de vivir con efectivo solo hoy y podrás sentir cómo cambia tu patrón de consumo.' },
    ],
  },
};
